def _load_env_file():
    """python-dotenv o'rnatilmagan bo'lsa ham .env faylini o'qiydi."""
    env_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), ".env")
    if not os.path.exists(env_path):
        return
    try:
        from dotenv import load_dotenv as _ld
        _ld(env_path)
        return
    except ImportError:
        pass  # manual o'qishga o'tamiz
    # Manual .env parser (python-dotenv o'rnatilmagan holat)
    try:
        with open(env_path, encoding="utf-8") as _f:
            for _line in _f:
                _line = _line.strip()
                if not _line or _line.startswith("#") or "=" not in _line:
                    continue
                _k, _, _v = _line.partition("=")
                _k = _k.strip()
                _v = _v.strip().strip('"').strip("'")
                if _k and _k not in os.environ:
                    os.environ[_k] = _v
    except OSError:
        pass

_load_env_file()
