def _model_rate(model_id: str, resolution: str = None):
    """Returns (rate, margin) tuple.
    MODEL_COST_USD qiymati:
      float                 → (float, MARGIN)          — barcha res bir xil narx
      dict → float value    → (float, MARGIN)          — per-res narx, global margin
      dict → {"rate","margin"} value → (rate, margin)  — per-res custom margin
    Qidiruv: aniq res → "default" kaliti → eng QIMMAT qiymat (hech qachon kam undirmaslik).
    """
    c = MODEL_COST_USD.get(model_id)
    if c is None:
        return (0.10, MARGIN)
    if isinstance(c, dict):
        if resolution and resolution in c:
            entry = c[resolution]
        elif "default" in c:
            entry = c["default"]
        else:
            # Hech qachon kam undirmaslik — eng qimmat qiymat
            def _erate(v):
                return v["rate"] if isinstance(v, dict) else float(v)
            entry = max(c.values(), key=_erate)
        if isinstance(entry, dict):
            return (float(entry["rate"]), float(entry.get("margin", MARGIN)))
        return (float(entry), MARGIN)
    return (float(c), MARGIN)

def calc_video_tangacha(model_id: str, resolution: str, duration: int) -> int:
    """ceil(rate × duration × margin / CREDIT_PRICE_USD).
    Per-resolution margin qo'llab-quvvatlanadi ({"rate": X, "margin": Y} format).
    """
    rate, margin = _model_rate(model_id, resolution)
    usd = rate * duration * margin
    return max(1, math.ceil(usd / CREDIT_PRICE_USD))

def calc_image_tangacha(model_id: str, resolution: str = None) -> int:
    """ceil(rate × margin / CREDIT_PRICE_USD)"""
    rate, margin = _model_rate(model_id, resolution)
    usd = rate * margin
    return max(1, math.ceil(usd / CREDIT_PRICE_USD))

def calc_video_stars(model_id: str, resolution: str, duration: int) -> int:
    rate, margin = _model_rate(model_id, resolution)
    usd = rate * duration * margin
    return max(1, math.ceil(usd / STAR_VALUE))

def calc_image_stars(model_id: str, resolution: str = None) -> int:
    rate, margin = _model_rate(model_id, resolution)
    usd = rate * margin
    return max(1, math.ceil(usd / STAR_VALUE))

def tangacha_to_stars(tangacha: int) -> int:
    """Faqat to'lov: foydalanuvchi nechta Stars to'laydi."""
    usd = tangacha * CREDIT_PRICE_USD
    return max(1, math.ceil(usd / STAR_VALUE))


