def load_pricing() -> bool:
    """pricing.json ni o'qib global narx o'zgaruvchilarini yangilaydi.
    Fayl yo'q yoki buzilgan bo'lsa — hozirgi (default) qiymatlar saqlanadi,
    WARNING log yoziladi, bot to'xtamaydi.
    Qaytaradi: True — muvaffaqiyat, False — xato."""
    global MARGIN, STAR_VALUE, CREDIT_PRICE_USD
    global FREE_STARTER_TANGACHA, DAILY_BONUS_AMOUNT
    global REFERRAL_PERCENT
    global ADMIN_CONTACT
    global FOTOSESSIYA_ENHANCE_FIRST
    try:
        if not os.path.exists(PRICING_FILE):
            logging.warning("load_pricing: %s topilmadi — default qiymatlar ishlatilmoqda", PRICING_FILE)
            return False
        with open(PRICING_FILE, encoding="utf-8") as f:
            data = json.load(f)

        # ── Skalyar qiymatlar ──────────────────────
        CREDIT_PRICE_USD        = float(data["credit_price_usd"])
        STAR_VALUE              = float(data["star_value"])
        MARGIN                  = float(data["margin"])
        FREE_STARTER_TANGACHA   = int(data["free_starter_tangacha"])
        DAILY_BONUS_AMOUNT      = int(data["daily_bonus_amount"])
        if "referral_percent" in data:
            REFERRAL_PERCENT = int(data["referral_percent"])
        # Admin kontakt (ixtiyoriy — yo'q bo'lsa default saqlanadi)
        if "admin_contact" in data:
            ADMIN_CONTACT = str(data["admin_contact"])

        # ── MODEL_COST_USD — in-place yangilash ──────────────────────────────
        MODEL_COST_USD.clear()
        MODEL_COST_USD.update(data["model_cost_usd"])

        # ── FOTOSESSIYA toggle ────────────────────────────────────────────────
        if "fotosessiya_enhance_first" in data:
            FOTOSESSIYA_ENHANCE_FIRST = bool(data["fotosessiya_enhance_first"])

        # ── TEMPLATE_COSTS — shablon uchun qat'iy narxlar (ixtiyoriy) ──────────
        # pricing.json da "template_costs": {"fotosessiya": 8} bo'lsa yangilanadi.
        # Yo'q bo'lsa — TEMPLATES dagi mavjud "cost" qiymati saqlanadi.
        if "template_costs" in data:
            for tmpl_id, tmpl_cost in data["template_costs"].items():
                if tmpl_id in _TEMPLATE_BY_ID:
                    _TEMPLATE_BY_ID[tmpl_id]["cost"] = int(tmpl_cost)

        # ── STAR_PACKAGES — fixed stars + bonus JSON dan olinadi ─────────────
        STAR_PACKAGES.clear()
        for pkg in data["star_packages"]:
            STAR_PACKAGES.append({
                "tangacha": int(pkg["tangacha"]),
                "bonus":    int(pkg.get("bonus", 0)),
                "stars":    int(pkg["stars"]),
                "emoji":    pkg["emoji"],
                "label":    pkg["label"],
                "desc":     pkg["desc"],
                "badge":    pkg.get("badge", ""),
            })

        logging.info("load_pricing: %s yuklandi (%d model narx, %d paket)",
                     PRICING_FILE, len(MODEL_COST_USD), len(STAR_PACKAGES))
        return True

    except Exception as e:
        logging.warning("load_pricing: o'qishda xato (%s) — mavjud qiymatlar saqlanadi", e)
        return False

