# ═══════════════════════════════════════════════════════════
#  ADMIN QO'SHGAN MODELLAR (sayt custom_models DB) — AVTOMATIK
# ═══════════════════════════════════════════════════════════
WEB_DB_PATH = "/opt/voro-web/voro_web.db"

def _load_custom_models_sync():
    """Sayt admin panelida qo'shilgan modellarni bot ro'yxatlariga qo'shadi.
    Faqat xavfsiz turlar: rasm-referensli video (dur jadvalli) va rasm modellari."""
    import sqlite3 as _sq, json as _json
    try:
        con = _sq.connect(f"file:{WEB_DB_PATH}?mode=ro", uri=True, timeout=3)
        con.row_factory = _sq.Row
        rows = con.execute("SELECT mid, config FROM custom_models WHERE enabled=1").fetchall()
        con.close()
    except Exception as e:
        logging.warning(f"custom_models o'qilmadi: {e}")
        return
    seen = set()
    for r in rows:
        try:
            mid = r["mid"]
            cfg = _json.loads(r["config"])
            rt = cfg.get("ref_types") or ["image"]
            pm = cfg.get("payload_map") or {}
            pr = cfg.get("pricing") or {}
            is_img = cfg.get("type") == "image"
            # Video/audio-referensli va per_sec (video uzunligiga bog'liq) — bot oqimiga mos emas, skip
            if ("video" in rt) or ("audio" in rt) or pm.get("video_field") or pm.get("audio_field"):
                continue
            if (not is_img) and (pr.get("per_sec") or not (cfg.get("dur") or [])):
                continue
            seen.add(mid)
            if any(m["id"] == mid for m in ALL_MODELS):
                # Meta/narxni yangilab qo'yamiz (admin tahrirlagan bo'lishi mumkin)
                pass
            else:
                card = {"id": mid, "name": f"{cfg.get('emoji','\u2728')} {cfg.get('name', mid)}", "_custom": True}
                (IMAGE_MODELS if is_img else VIDEO_MODELS).append(card)
                ALL_MODELS.append(card)
            # ── META ──
            durs = [int(d) for d in (cfg.get("dur") or [])]
            meta = {
                "badge": "\U0001F195 Yangi",
                "resolutions": cfg.get("res") or ([] if is_img else ["720p"]),
                "aspects": cfg.get("asp") or [],
                "refs": int(cfg.get("refs") or 0),
                "refs_req": bool(cfg.get("refs_req")),
                "hook": cfg.get("hook") or "",
                "best_for": cfg.get("hook") or "",
                "tip": "",
            }
            if durs:
                meta["dur_steps"] = durs
                meta["min_dur"], meta["max_dur"] = min(durs), max(durs)
            if pm.get("image_single"):
                meta["ref_param"] = pm.get("image_field") or "image"
            elif pm.get("image_field"):
                meta["ref_array_field"] = pm["image_field"]
            else:
                meta["ref_array_field"] = "images"
            if pm.get("send_aspect") is False or not meta["aspects"]:
                meta["no_aspect_param"] = True
            elif pm.get("aspect_key"):
                meta["aspect_field"] = pm["aspect_key"]
            if pm.get("send_resolution") is False:
                meta["no_resolution_param"] = True
            if pm.get("send_duration") is False:
                meta["no_duration_param"] = True
            elif pm.get("duration_key"):
                meta["dur_field"] = pm["duration_key"]
            MODEL_META[mid] = meta
            # ── NARX: sayt tangasi -> bot USD (joriy bot kursi bilan, margin 1.0) ──
            cred = CREDIT_PRICE_USD
            if is_img and pr.get("res"):
                MODEL_COST_USD[mid] = {rk: {"rate": float(v) * cred, "margin": 1.0}
                                       for rk, v in pr["res"].items()}
            elif pr.get("dur") and durs:
                d0 = str(min(durs))
                base = float(pr["dur"].get(d0) or pr["dur"].get(min(durs)) or 0)
                if base > 0:
                    per_sec_coin = base / min(durs)
                    MODEL_COST_USD[mid] = {"default": {"rate": per_sec_coin * cred, "margin": 1.0}}
        except Exception as e:
            logging.warning(f"custom model {r['mid'] if r else '?'} yuklanmadi: {e}")
    # O'chirilgan customlarni ro'yxatdan olib tashlash
    for lst in (VIDEO_MODELS, IMAGE_MODELS, ALL_MODELS):
        lst[:] = [m for m in lst if not (m.get("_custom") and m["id"] not in seen)]
    if seen:
        logging.info(f"Custom modellar yuklandi: {sorted(seen)}")

def _start_custom_models_watcher():
    """Startupda yuklab, har 60s yangilab turadi (admin qo'shsa bot avtomatik ko'radi)."""
    import threading
    _load_custom_models_sync()
    def _loop():
        while True:
            time.sleep(60)
            try:
                _load_custom_models_sync()
            except Exception:
                pass
    threading.Thread(target=_loop, daemon=True, name="custom-models-watcher").start()


