# ── Futbolchi tanlash: samples.json dan dinamik keyboard ──────────────────

def _build_player_pick_keyboard(cb_prefix: str, back_cb: str,
                                 extra_rows: list | None = None) -> list:
    """samples.json dagi player/* kalitlardan dinamik futbolchi tanlash klaviaturasi."""
    _sdata = _samples_load()
    _btns = []
    for _nk, _label in _UZ_PLAYER_LABELS.items():
        if f"player/{_nk}" in _sdata:
            _btns.append(InlineKeyboardButton(_label, callback_data=f"{cb_prefix}:{_nk}"))
    _rows = [_btns[i:i+2] for i in range(0, len(_btns), 2)]
    if extra_rows:
        _rows.extend(extra_rows)
    _rows.append([InlineKeyboardButton(T("back"), callback_data=back_cb)])
    return _rows


async def _player_b64_from_sample(bot, nk: str):
    """player/{nk} kaliti bo'yicha samples.json dan rasmni yuklab, bytes qaytaradi."""
    _samp = _sample_get(f"player/{nk}")
    if not _samp:
        return None
    try:
        _fobj = await bot.get_file(_samp["file_id"])
        return bytes(await _fobj.download_as_bytearray())
    except Exception as _e:
        logging.warning(f"_player_b64_from_sample xato nk={nk!r}: {_e}")
        return None


