#  USER BALANCE
# ════════════════════════════════════════════════════
def load_users():
    if not os.path.exists(USERS_FILE):
        return {}
    try:
        with open(USERS_FILE) as f:
            return json.load(f)
    except json.JSONDecodeError as e:
        logging.error("users.json buzilgan (%s) — .bak dan tiklanmoqda", e)
        bak = USERS_FILE + ".bak"
        if not os.path.exists(bak):
            logging.critical("users.json.bak ham topilmadi — to'xtatilmoqda")
            sys.exit(1)
        try:
            with open(bak) as f:
                data = json.load(f)
            logging.warning("users.json.bak dan muvaffaqiyatli tiklandi")
            return data
        except json.JSONDecodeError as e2:
            logging.critical("users.json.bak ham buzilgan (%s) — to'xtatilmoqda", e2)
            sys.exit(1)

def save_users(d):
    tmp = USERS_FILE + ".tmp"
    if os.path.exists(USERS_FILE):
        shutil.copy2(USERS_FILE, USERS_FILE + ".bak")
    with open(tmp, "w") as f:
        json.dump(d, f, indent=2, ensure_ascii=False)
    os.replace(tmp, USERS_FILE)

def _users_tx(mutator):
    """Atomik read-modify-write tranzaksiya users.json uchun.
    mutator(users: dict) -> any  ni RLock ichida bajaradi, so'ng save_users() chaqiradi.
    RLock reentrant — get_user() va add_tangacha() bir-birini chaqirsa deadlock yo'q."""
    with _users_lock:
        users = load_users()
        r = mutator(users)
        save_users(users)
        return r

# ── Generatsiya tarixi ────────────────────────────────────────
def load_history() -> dict:
    """history.json ni yuklaydi. Buzilgan bo'lsa .bak dan tiklashga urinadi."""
    if not os.path.exists(HISTORY_FILE):
        return {}
    try:
        with open(HISTORY_FILE, encoding="utf-8") as f:
            return json.load(f)
    except (json.JSONDecodeError, OSError) as e:
        logging.warning("history.json buzilgan (%s) — .bak dan tiklanmoqda", e)
        bak = HISTORY_FILE + ".bak"
        if os.path.exists(bak):
            try:
                with open(bak, encoding="utf-8") as f:
                    data = json.load(f)
                logging.warning("history.json.bak dan muvaffaqiyatli tiklandi")
                return data
            except (json.JSONDecodeError, OSError) as e2:
                logging.error("history.json.bak ham buzilgan (%s) — bo'sh dict qaytarildi", e2)
        return {}

async def save_history(uid: int, entry: dict) -> None:
    """
    Berilgan entry ni history.json ga atomic yozadi.
    Har user uchun faqat oxirgi HISTORY_LIMIT ta yozuv saqlanadi.

    entry = {
        "ts":      ISO-8601 vaqt (UTC),
        "model":   model_id,
        "prompt":  to'liq prompt,
        "cost":    tangacha miqdori (int),
        "type":    "video" | "image",
        "file_id": Telegram file_id yoki None,
    }
    """
    async with _history_lock:
        data = load_history()
        key = str(uid)
        records = data.get(key, [])
        records.append(entry)
        data[key] = records[-HISTORY_LIMIT:]
        if os.path.exists(HISTORY_FILE):
            shutil.copy2(HISTORY_FILE, HISTORY_FILE + ".bak")
        tmp = HISTORY_FILE + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
        os.replace(tmp, HISTORY_FILE)

