def load_promos() -> dict:
    """promos.json ni yuklaydi. Buzilgan bo'lsa .bak dan tiklashga urinadi."""
    if not os.path.exists(PROMOS_FILE):
        return {}
    try:
        with open(PROMOS_FILE, encoding="utf-8") as f:
            return json.load(f)
    except (json.JSONDecodeError, OSError) as e:
        logging.warning("promos.json buzilgan (%s) — .bak dan tiklanmoqda", e)
        bak = PROMOS_FILE + ".bak"
        if os.path.exists(bak):
            try:
                with open(bak, encoding="utf-8") as f:
                    data = json.load(f)
                logging.warning("promos.json.bak dan muvaffaqiyatli tiklandi")
                return data
            except (json.JSONDecodeError, OSError) as e2:
                logging.error("promos.json.bak ham buzilgan (%s) — bo'sh dict qaytarildi", e2)
        return {}

def save_promos(data: dict) -> None:
    """promos.json ga atomic yozadi (.tmp + os.replace). Avval .bak nusxasi."""
    if os.path.exists(PROMOS_FILE):
        shutil.copy2(PROMOS_FILE, PROMOS_FILE + ".bak")
    tmp = PROMOS_FILE + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    os.replace(tmp, PROMOS_FILE)

# ── Kunlik bonus ──────────────────────────────────────────────
DAILY_BONUS_AMOUNT = 2   # tangacha

# Barcha default o'zgaruvchilar aniqlanganidan keyin pricing.json o'qilinadi
# (STAR_PACKAGES, DAILY_BONUS_AMOUNT va boshqalar allaqachon mavjud)
load_pricing()

async def check_and_give_daily_bonus(uid: int) -> tuple[int, int]:
    """
    Foydalanuvchiga kunlik bonusni bir marta beradi.

    Qaytaradi: (bonus, streak)
        bonus  = berilgan tangacha soni (0 = allaqachon berilgan)
        streak = joriy ketma-ket kunlar soni
    """
    today     = str(datetime.now().date())
    yesterday = str((datetime.now() - timedelta(days=1)).date())
    result = [0, 0]  # [bonus, streak]
    def _mutate(users):
        k = str(uid)
        if k not in users:
            return
        u = users[k]
        if u.get("last_bonus_date") == today:
            result[1] = u.get("streak", 0)
            return   # o'zgarish yo'q — save_users bir xil datani yozadi (zararsiz)
        streak = (u.get("streak", 0) + 1
                  if u.get("last_bonus_date") == yesterday
                  else 1)
        u["last_bonus_date"] = today
        u["streak"]          = streak
        users[k] = u
        result[0] = DAILY_BONUS_AMOUNT
        result[1] = streak
    _users_tx(_mutate)
    if result[0]:
        # tangacha DB-aware yo'l bilan qo'shiladi (web DB'dagi userlar uchun DB'ga)
        await add_tangacha(uid, DAILY_BONUS_AMOUNT)
    return result[0], result[1]

def get_user(uid: int) -> dict:
    """Foydalanuvchi ma'lumotlarini RLock ichida atomik yuklaydi.
    Yaratish / migratsiya / maydon qo'shish / last_active yangilash ham shu tranzaksiya ichida."""
    today = str(datetime.now().date())
    def _mutate(users):
        k = str(uid)
        if k not in users:
            users[k] = {"tangacha": FREE_STARTER_TANGACHA, "total": 0, "joined": today,
                        "last_active": today, "stars_paid": 0, "referrals": [],
                        "referred_by": None, "ref_earned": 0, "referral_rewarded": False,
                        "banned": False}
        u = users[k]
        # Migrate old "stars" field → tangacha
        if "stars" in u and "tangacha" not in u:
            u["tangacha"] = u.pop("stars") * 10
        # Add missing fields to old accounts
        for field, default in [("last_active", today), ("stars_paid", 0), ("referrals", []),
                                ("referred_by", None), ("ref_earned", 0), ("referral_rewarded", False),
                                ("banned", False), ("last_bonus_date", None), ("streak", 0),
                                ("lang", None)]:
            if field not in u:
                u[field] = default
        # Update last_active daily
        if u.get("last_active") != today:
            u["last_active"] = today
        users[k] = u
        return u
    return _users_tx(_mutate)

# ── voro.uz web DB (balans manbai: DB'da bor userlar uchun) ──
def _webdb():
    c = sqlite3.connect("/opt/voro-web/voro_web.db", timeout=5)
    c.execute("PRAGMA journal_mode=WAL")
    return c

def _db_user_exists(uid) -> bool:
    try:
        c = _webdb()
        try:
            r = c.execute("SELECT 1 FROM users WHERE tg_id=?", (uid,)).fetchone()
        finally:
            c.close()
        return bool(r)
    except Exception:
        return False

def get_balance(uid: int) -> int:
    if _db_user_exists(uid):
        try:
            c = _webdb()
            try:
                r = c.execute("SELECT balance FROM users WHERE tg_id=?", (uid,)).fetchone()
            finally:
                c.close()
            if r is not None:
                return int(r[0] or 0)
        except Exception as e:
            logger.warning(f"get_balance: web DB xato, users.json'ga qaytildi: {e}")
    return get_user(uid).get("tangacha", 0)

async def add_tangacha(uid: int, amount: int):
    if _db_user_exists(uid):
        try:
            c = _webdb()
            try:
                c.execute("UPDATE users SET balance=balance+? WHERE tg_id=?", (amount, uid))
                c.commit()
            finally:
                c.close()
            return
        except Exception as e:
            logger.warning(f"add_tangacha: web DB xato, users.json'ga qaytildi: {e}")
    today = str(datetime.now().date())
    def _mutate(users):
        k = str(uid)
        if k not in users:
            # Foydalanuvchi yo'q — standart qiymatlar bilan yaratamiz
            users[k] = {"tangacha": FREE_STARTER_TANGACHA, "total": 0, "joined": today,
                        "last_active": today, "stars_paid": 0, "referrals": [],
                        "referred_by": None, "ref_earned": 0, "referral_rewarded": False,
                        "banned": False, "last_bonus_date": None, "streak": 0}
        users[k]["tangacha"] = users[k].get("tangacha", 0) + amount
    _users_tx(_mutate)

async def deduct_tangacha(uid: int, amount: int) -> bool:
    if _db_user_exists(uid):
        try:
            c = _webdb()
            try:
                cur = c.execute(
                    "UPDATE users SET balance=balance-? WHERE tg_id=? AND balance>=?",
                    (amount, uid, amount))
                if cur.rowcount == 1:
                    c.commit()
                    ok = True
                else:
                    c.rollback()
                    ok = False
            finally:
                c.close()
        except Exception as e:
            logger.warning(f"deduct_tangacha: web DB xato: {e}")
            return False
        if ok:
            # statistika: users.json'dagi total hisoblagichi avvalgidek oshadi
            def _mutate(users):
                k = str(uid)
                if k in users:
                    users[k]["total"] = users[k].get("total", 0) + 1
            _users_tx(_mutate)
        return ok
    result = [False]
    def _mutate(users):
        k = str(uid)
        if users.get(k, {}).get("tangacha", 0) < amount:
            return   # result[0] False qoladi — manfiy balans yo'q
        users[k]["tangacha"] -= amount
        users[k]["total"] = users[k].get("total", 0) + 1
        result[0] = True
    _users_tx(_mutate)
    return result[0]

