def get_model(mid): return next((m for m in ALL_MODELS if m["id"] == mid), None)
def is_video(mid):  return any(m["id"] == mid for m in VIDEO_MODELS)

def model_info_text(mid: str, balance: int) -> str:
    m = get_model(mid); meta = MODEL_META.get(mid, {})
    badge     = meta.get("badge", "")
    hook      = _tr_label(meta.get("hook", ""))
    best_for  = _tr_label(meta.get("best_for", ""))
    tip       = _tr_label(meta.get("tip", ""))
    refs      = meta.get("refs", 0)
    audio     = meta.get("audio", False)
    res_inline = meta.get("res_inline", False)

    if is_video(mid):
        mn  = meta.get("min_dur", 1)
        mx  = meta.get("max_dur", 8)
        res = meta.get("resolutions", ["720p"])
        _info_api_map = meta.get("res_api_map", {})
        # __TBD__ resolutionlarni ekranda ko'rsatmaslik
        res_visible = [r for r in res if _info_api_map.get(r) != "__TBD__"]
        if not res_visible:
            res_visible = res   # hech narsa qolmasa hammasini ko'rsat
        dflt_res = "720p" if "720p" in res_visible else res_visible[0]
        dur_steps = meta.get("dur_steps", [])
        # Narx satrini dur_steps yoki min/max dan hosil qilamiz
        if dur_steps and len(dur_steps) > 1:
            price_parts = [f"{d}s = ⚡️{calc_video_tangacha(mid, dflt_res, d)}" for d in dur_steps]
            prices = "  |  ".join(price_parts)
        elif mn == mx:
            prices = f"{mn}s = ⚡️{calc_video_tangacha(mid, dflt_res, mn)}"
        else:
            p1  = calc_video_tangacha(mid, dflt_res, mn)
            pmx = calc_video_tangacha(mid, dflt_res, mx)
            mid_dur = min(5, mx) if mn < 5 < mx else None
            if mid_dur:
                p5     = calc_video_tangacha(mid, dflt_res, mid_dur)
                prices = f"{mn}s = ⚡️{p1}  |  {mid_dur}s = ⚡️{p5}  |  {mx}s = ⚡️{pmx}"
            else:
                prices = f"{mn}s = ⚡️{p1}  |  {mx}s = ⚡️{pmx}"
        # Davomiylik qatori
        if mn == mx:
            dur_label = f"<b>{mn} {T('w_seconds')}</b>"
        else:
            dur_label = f"<b>{mn}–{mx} {T('w_seconds')}</b>"
        if res_inline:
            dur_line = f"⏱ {T('w_duration')}: {dur_label}"
        else:
            dur_line = f"⏱ {T('w_duration')}: {dur_label}" + ("" if mn == mx else T('w_persec_note'))
        audio_val  = T("w_audio_yes") if audio else T("w_no")
        audio_line = f"🎵 Audio: <b>{audio_val}</b>"
        res_line   = f"🖥 {T('w_resolutions')}: <b>{' · '.join(res_visible)}</b>"
        req_label  = T("w_required2") if meta.get("refs_req") else T("w_optional")
        ref_line   = (f"📎 {T('w_ref_img')}: <b>{refs} {T('w_ref_attach')}</b>\n"
                      f"   <i>({req_label})</i>") if refs else T("w_ref_none_t2v")
        elem_line  = T("w_elem_yes") if _model_supports_elem_ref(mid) else ""
    else:
        img_res = meta.get("resolutions", [])
        if img_res:
            p_min = calc_image_tangacha(mid, img_res[0])
            p_max = calc_image_tangacha(mid, img_res[-1])
            if len(img_res) > 1:
                prices = f"⚡️{p_min} ({img_res[0]}) — ⚡️{p_max} ({img_res[-1]})"
            else:
                prices = f"⚡️{p_min}"
            res_line = f"🖥 {T('w_resolutions')}: <b>{' · '.join(img_res)}</b>"
        else:
            prices = f"⚡️{calc_image_tangacha(mid)}"
            res_line = ""
        dur_line   = ""
        audio_line = ""
        elem_line  = ""
        ref_line   = (f"📎 Reference: <b>{refs}</b> {T('w_req_paren') if meta.get('refs_req') else T('w_opt_paren')}" if refs
                      else T("w_ref_none_t2i"))

    if res_inline:
        # Kompakt format: badge yo'q, 🎯 prefix, narx qisqa
        price_header = dflt_res if is_video(mid) else T("w_1img")
        lines = [f"<b>{m['name']}</b>\n"]
        if hook:   lines.append(f"{hook}")
        if best_for: lines.append(f"🎯 {best_for}")
        if dur_line:   lines.append(dur_line)
        if audio_line: lines.append(audio_line)
        if res_line:   lines.append(res_line)
        lines.append(ref_line)
        if elem_line:  lines.append(elem_line)
        lines += [
            f"\n<b>💰 ({price_header}):</b>  {prices}",
            f"\n{tip}" if tip else "",
            f"\n💫 {T('w_yourbal')}: <b>⚡️{balance}</b>",
        ]
        return "\n".join(l for l in lines if l != "")

    # Standart format
    title = f"{badge}  <b>{m['name']}</b>" if badge else f"<b>{m['name']}</b>"
    lines = [
        f"{title}\n",
        f"<i>{hook}</i>\n",
        f"🎯 {T('w_best')}: <b>{best_for}</b>",
    ]
    if dur_line:   lines.append(dur_line)
    if audio_line: lines.append(audio_line)
    if res_line:   lines.append(res_line)
    lines.append(ref_line)
    if elem_line:  lines.append(elem_line)
    price_header = dflt_res if is_video(mid) else T("w_1img")
    lines += [
        f"\n<b>💰 {T('w_price')} ({price_header}):</b>  {prices}",
        f"\n{tip}",
        f"\n💫 {T('w_yourbal')}: <b>⚡️{balance}</b>",
    ]
    return "\n".join(lines)

def res_kb(mid: str):
    meta = MODEL_META.get(mid, {}); resolutions = meta.get("resolutions", ["720p"])
