def persistent_kb(uid: int = 0, for_group: bool = False, first_name: str = ""):
    """Doim pastda ko'rinadigan ReplyKeyboard.
    uid berilsa Studio URL'iga joriy balans + imzolangan uid/ism qo'shib yuboradi
    (klaviatura tugmasidan ochilgan Mini App'ga Telegram initData bermaydi).
    for_group=True: WebApp tugmasi YO'Q (guruhda WebApp ishlamaydi → BadRequest).
    """
    bal = get_balance(uid) if uid else 0
    studio_url = f"{MINI_APP_URL}&bal={bal}"
    if uid:
        _sig = hmac.new(hashlib.sha256(BOT_TOKEN.encode()).digest(),
                        str(uid).encode(), hashlib.sha256).hexdigest()[:32]
        studio_url += f"&uid={uid}&n={urllib.parse.quote((first_name or '')[:40])}&sig={_sig}"
    rows = []
    if not for_group:
        rows.append([KeyboardButton(T("rk_miniapp", uid), web_app=WebAppInfo(studio_url))])
    rows += [
        [KeyboardButton(T("rk_create", uid)),    KeyboardButton(T("rk_create_image", uid))],
        [KeyboardButton(T("rk_templates", uid)),  KeyboardButton(T("rk_topup", uid))],
        [KeyboardButton(T("rk_balance", uid)),      KeyboardButton(T("rk_referral", uid))],
        [KeyboardButton(T("rk_guide", uid)),   KeyboardButton(T("rk_history", uid))],
        [KeyboardButton(T("rk_vagent", uid)),  KeyboardButton(T("rk_lang", uid))],
    ]
    return ReplyKeyboardMarkup(rows, resize_keyboard=True, is_persistent=True)

