def upsell_kb(model_id: str, res: str, dur: int, cat: str):
    rows = []
    if cat == "video":
        if res != "1080p" and "1080p" in MODEL_META.get(model_id, {}).get("resolutions", []):
            cost = calc_video_tangacha(model_id, "1080p", dur)
            rows.append([InlineKeyboardButton(f"⬆️ 1080p bilan qayta — {cost}⚡️", callback_data=f"UPSELL:1080p:{dur}")])
        if dur < MODEL_META.get(model_id, {}).get("max_dur", 8):
            new_dur = min(dur + 2, MODEL_META[model_id]["max_dur"])
            cost = calc_video_tangacha(model_id, res, new_dur)
            rows.append([InlineKeyboardButton(f"⏫ {new_dur}s bilan qayta — {cost}⚡️", callback_data=f"UPSELL:{res}:{new_dur}")])
    rows.append([InlineKeyboardButton(T("create_more"), callback_data=f"cat:{'video' if cat=='video' else 'image'}")])
    rows.append([InlineKeyboardButton(T("home"),   callback_data="home")])
    return InlineKeyboardMarkup(rows)



async def _ai_gen(
    context: ContextTypes.DEFAULT_TYPE,
    uid: int, chat_id: int, status_msg,
    mid: str, model_name: str,
    res: str, dur: int, asp: str, cat: str, idea: str,
):
    """
    Shared AI-mode generation core.
    status_msg — an existing Message we can edit() for progress updates.
    """
    cost = calc_video_tangacha(mid, res, dur) if is_video(mid) else calc_image_tangacha(mid, res)
    bal  = get_balance(uid)

    if bal < cost:
        await status_msg.edit_text(
            T("fs105", v0=(cost), v1=(bal)),
            parse_mode="HTML", reply_markup=lowbalance_kb())
        return

    try:
        out_type = "video" if cat == "video" else "rasm"
        prompt   = idea
        short_p  = prompt[:100] + ("…" if len(prompt) > 100 else "")

        await status_msg.edit_text(
            T("fs10", v0=(model_name))
            + (f"  |  🖥 {res}  |  ⏱ {dur}s" if is_video(mid) else "")
            + f"\n✅ Prompt: <i>{short_p}</i>\n\n🚀 Voro AI ga yuborilmoqda...",
            parse_mode="HTML")

        ref_base64s_ai   = context.user_data.get("ref_base64s", [])
        ref_audio_b64s_ai= context.user_data.get("ref_audio_b64s", [])
        ref_vc_b64s_ai   = context.user_data.get("ref_vid_clip_b64s", [])
        ref_video        = context.user_data.get("ref_video_url")

        # Re-upload all refs from b64 to get fresh Atlas URLs
        ai_img_urls = []
        ai_aud_urls = []
        ai_vc_urls  = []
        for i, b64 in enumerate(ref_base64s_ai):
            try:
                img_bytes = base64.b64decode(b64)
                ct = ("image/png" if img_bytes[:8] == b'\x89PNG\r\n\x1a\n'
                      else "image/gif" if img_bytes[:6] in (b'GIF87a', b'GIF89a')
                      else "image/jpeg")
                ext = ct.split("/")[1]
                u = await atlas_upload_media(bytes(img_bytes), filename=f"ai_img_{i}.{ext}", content_type=ct)
                if u: ai_img_urls.append(u)
            except Exception as e:
                logger.warning(f"_ai_gen img {i+1} upload error: {e}")
        for i, item in enumerate(ref_audio_b64s_ai):
            try:
                u = await atlas_upload_media(
                    base64.b64decode(item["b64"]),
                    filename=f"ai_aud_{i}.{item['ext']}", content_type=item["ctype"])
                if u: ai_aud_urls.append(u)
            except Exception as e:
                logger.warning(f"_ai_gen audio {i+1} upload error: {e}")
        for i, item in enumerate(ref_vc_b64s_ai):
            try:
                u = await atlas_upload_media(
                    base64.b64decode(item["b64"]),
                    filename=f"ai_vc_{i}.{item['ext']}", content_type=item["ctype"])
                if u: ai_vc_urls.append(u)
            except Exception as e:
                logger.warning(f"_ai_gen vidclip {i+1} upload error: {e}")

        # ── Fallback: qayta yuklash muvaffaqiyatsiz bo'lsa, saqlangan URL lardan foydalanamiz ──
        if not ai_img_urls and ref_base64s_ai:
            _st = context.user_data.get("ref_urls", [])
            if _st:
                ai_img_urls = list(_st)
                logger.warning(f"_ai_gen: img re-upload failed — {len(_st)} saqlangan URL ishlatilmoqda")
        if not ai_aud_urls and ref_audio_b64s_ai:
            _st = context.user_data.get("ref_audio_urls", [])
            if _st:
                ai_aud_urls = list(_st)
                logger.warning(f"_ai_gen: audio re-upload failed — {len(_st)} saqlangan URL ishlatilmoqda")
        if not ai_vc_urls and ref_vc_b64s_ai:
            _st = context.user_data.get("ref_video_clip_urls", [])
            if _st:
                ai_vc_urls = list(_st)
                logger.warning(f"_ai_gen: vidclip re-upload failed — {len(_st)} saqlangan URL ishlatilmoqda")

        submit = await atlas_submit(
            mid, prompt, asp,
            resolution=(res if res not in (None, "default") else None),
            duration=dur if is_video(mid) and dur > 0 else None,
            image_urls=ai_img_urls if ai_img_urls else None,
            video_url=ref_video,
            audio_urls=ai_aud_urls if ai_aud_urls else None,
            video_clip_urls=ai_vc_urls if ai_vc_urls else None)
        logger.info(f"_ai_gen submit: {submit}")

        err_code = submit.get("code") or (submit.get("data") or {}).get("code")
        if err_code == 402 or "insufficient" in (submit.get("msg") or "").lower():
            raise Exception("SERVER_LOW_BALANCE")
        if submit.get("error") or submit.get("status") == "error":
            raise Exception(submit.get("message") or str(submit))

        data = submit.get("data") or {}
        pid  = data.get("id")
        if not pid:
            raise Exception(f"SERVER_ERROR:{json.dumps(submit)[:200]}")

        # ── Animatsiyali loading + polling parallel ──
        _stop_anim = asyncio.Event()
        _anim_task = asyncio.create_task(
            _animate_generation(status_msg, model_name, cat, res, dur, pid, _stop_anim)
        )
        try:
            final = await atlas_poll(pid)
        finally:
            _stop_anim.set()
            _anim_task.cancel()
            try:
                await _anim_task
            except asyncio.CancelledError:
                pass
        fd = final.get("data") or {}
        st = fd.get("status", "")

        if st in ATLAS_DONE_STATUSES:
            out_arr = fd.get("outputs") or fd.get("images") or fd.get("urls") or []
            if out_arr:
                media_url = out_arr[0] if isinstance(out_arr, list) else str(out_arr)
            else:
                out_s = fd.get("output")
                if isinstance(out_s, list) and out_s: media_url = out_s[0]
                elif isinstance(out_s, str):           media_url = out_s
                else:
                    media_url = next(
                        (fd.get(f) for f in ("url","image_url","video_url","result","media_url") if fd.get(f)),
                        None)
            _ded_ok = await deduct_tangacha(uid, cost)
            if not _ded_ok:
                logger.error(f"deduct_tangacha FAILED uid={uid} cost={cost} — kredit yetmadi")
            nb = get_balance(uid)
            caption = (
                f"✅ <b>{model_name}</b>"
                + (f"  |  {res}  |  {dur}s" if is_video(mid) else "")
                + f"  |  {asp}\n\n<i>{short_p}</i>\n\n" + T("gx23", v0=(nb))
            )
            try: await status_msg.delete()
            except: pass
            if media_url:
                _url_lo = media_url.lower().split("?")[0]
                _is_vid = any(_url_lo.endswith(e) for e in (".mp4",".webm",".mov",".avi",".gif"))
                try:
                    if _is_vid:
                        await context.bot.send_video(chat_id=chat_id, video=media_url, caption=caption, parse_mode="HTML")
                    else:
                        await context.bot.send_photo(chat_id=chat_id, photo=media_url, caption=caption, parse_mode="HTML")
                except Exception:
                    try:
                        if _is_vid:
                            await context.bot.send_photo(chat_id=chat_id, photo=media_url, caption=caption, parse_mode="HTML")
                        else:
                            await context.bot.send_video(chat_id=chat_id, video=media_url, caption=caption, parse_mode="HTML")
                    except Exception:
                        await context.bot.send_document(chat_id=chat_id, document=media_url, caption=caption, parse_mode="HTML")
            # Birinchi muvaffaqiyatli generatsiya (total=1 demak endigina birinchi bo'ldi)
            _is_first = get_user(uid).get("total", 0) == 1
            if nb < 50:
                await context.bot.send_message(
                    chat_id=chat_id,
                    text=T("emt32", v0=(nb)),
                    parse_mode="HTML", reply_markup=lowbalance_kb())
            elif _is_first:
                await context.bot.send_message(
                    chat_id=chat_id,
                    text=T("emt20", v0=(nb)),
                    parse_mode="HTML",
                    reply_markup=InlineKeyboardMarkup([
                        [InlineKeyboardButton(T("topup_credit"), callback_data="buy")],
                        [InlineKeyboardButton(T("create_more"), callback_data=f"cat:{'video' if cat=='video' else 'image'}")],
                    ]))
            else:
                await context.bot.send_message(
                    chat_id=chat_id,
                    text=T("emt33", v0=(nb)),
                    parse_mode="HTML",
                    reply_markup=upsell_kb(mid, res, dur, cat))

        elif st in ATLAS_FAILED_STATUSES:
            # Xom JSON/dict userga ko'rsatilmasin — logga to'liq, userga qisqa
            _err_raw = fd.get("error") or fd.get("message") or fd.get("msg") or str(fd)
            _err_str = _err_raw if isinstance(_err_raw, str) else json.dumps(_err_raw, ensure_ascii=False)
            logger.error(f"atlas_gen FAILED [{mid}]: {_err_str}")
            _el = _err_str.lower()
            if "use case not supported" in _el:
                _clean = T("va_usecase")
            elif "content" in _el and ("policy" in _el or "violat" in _el or "safety" in _el):
                _clean = T("va_policy")
            elif "quota" in _el or "rate limit" in _el:
                _clean = T("va_ratelimit")
            elif "resolution" in _el or "invalid" in _el or "parameter" in _el:
                _clean = T("va_badparam", v0=(_err_str[:150]))
            else:
                _clean = T("va_genfail", v0=(_err_str[:200]))
            await status_msg.edit_text(_clean, parse_mode="HTML", reply_markup=back_home_kb())
        elif st == "timeout":
            await status_msg.edit_text(T("m_time7"), reply_markup=back_home_kb())
        else:
            await status_msg.edit_text(T("fs74", v0=(st)), parse_mode="HTML", reply_markup=back_home_kb())

    except Exception as e:
        logger.exception("_ai_gen error")
        es = str(e)
        if "SERVER_LOW_BALANCE" in es:
            msg = (T("rt10"))
        elif es.startswith("SERVER_ERROR:"):
            msg = T("va_badresp")
        else:
            # Xom JSON/stack trace yashirish: faqat birinchi qator
            _first = es.splitlines()[0][:200] if es.splitlines() else es[:200]
            if _first.lstrip().startswith("{") or _first.lstrip().startswith("["):
                msg = T("va_unexpected")
            else:
                msg = f"⚠️ <b>Xato:</b> <code>{_first}</code>"
        try: await status_msg.edit_text(msg, parse_mode="HTML", reply_markup=back_home_kb())
        except: pass


ATLAS_IMG_MIN_PX = 450_000
ATLAS_IMG_MAX_PX = 8_200_000

def _normalize_atlas_image(file_bytes: bytes, content_type: str) -> bytes:
    """Atlas talabi (409,600..8,847,360 px): kichik rasmni kattalashtirish, kattasini kichraytirish."""
    try:
        from PIL import Image
        import io as _io
        img = Image.open(_io.BytesIO(file_bytes)); img.load()
        w, h = img.size; px = w * h
        if ATLAS_IMG_MIN_PX <= px <= ATLAS_IMG_MAX_PX:
            return file_bytes
        scale = (ATLAS_IMG_MIN_PX / px) ** 0.5 if px < ATLAS_IMG_MIN_PX else (ATLAS_IMG_MAX_PX / px) ** 0.5
        nw, nh = max(1, round(w * scale)), max(1, round(h * scale))
        img = img.resize((nw, nh), Image.LANCZOS)
        buf = _io.BytesIO()
        if "png" in (content_type or ""):
            img.save(buf, "PNG")
        elif "webp" in (content_type or ""):
            img.save(buf, "WEBP", quality=92)
        else:
            img.convert("RGB").save(buf, "JPEG", quality=92)
        logger.info(f"atlas_normalize: {w}x{h} ({px}px) -> {nw}x{nh}")
        return buf.getvalue()
    except Exception as _e:
        logger.warning(f"atlas_normalize xato: {_e}")
        return file_bytes


async def atlas_upload_media(file_bytes: bytes, filename="ref.jpg", content_type: str = None) -> str:
    """Rasm yoki videoni AtlasCloud ga yuklab, uning URL ini qaytaradi."""
    if content_type is None:
        # Fayl turini magic bytes orqali aniqlaymiz
        if file_bytes[:3] == b'\xff\xd8\xff':
            content_type = "image/jpeg"
        elif file_bytes[:8] == b'\x89PNG\r\n\x1a\n':
            content_type = "image/png"
        elif file_bytes[:4] in (b'ftyp', b'\x00\x00\x00\x18', b'\x00\x00\x00\x1c'):
            content_type = "video/mp4"
        elif file_bytes[:4] == b'RIFF' and file_bytes[8:12] == b'AVI ':
            content_type = "video/avi"
        elif file_bytes[:3] == b'ID3' or file_bytes[:2] == b'\xff\xfb':
            content_type = "audio/mpeg"
        else:
            content_type = "image/jpeg"  # default
    if content_type and content_type.startswith("image/"):
        file_bytes = _normalize_atlas_image(file_bytes, content_type)
    url = f"{ATLASCLOUD_BASE}/api/v1/model/uploadMedia"
    headers = {"Authorization": f"Bearer {ATLASCLOUD_API_KEY}"}
    form = aiohttp.FormData()
    form.add_field("file", file_bytes, filename=filename, content_type=content_type)
    async with aiohttp.ClientSession() as s:
        async with s.post(url, headers=headers, data=form, timeout=aiohttp.ClientTimeout(total=60)) as r:
            resp = await r.json()
            logger.info(f"atlas_upload_media RAW response: {resp}")
            d = resp.get("data") or {}
            # Barcha mumkin bo'lgan Atlas URL field nomlarini tekshiramiz
            checked = {}
            for _f in ("url", "download_url", "fileUrl", "file_url",
                       "mediaUrl", "media_url", "downloadUrl", "cdnUrl",
                       "presignedUrl", "objectUrl", "imageUrl", "fileLink",
                       "publicUrl", "accessUrl"):
                v = resp.get(_f) or d.get(_f)
                checked[_f] = v
                if v and isinstance(v, str) and v.startswith("http"):
                    logger.info(f"atlas_upload_media: URL topildi field='{_f}' url={v[:80]}")
                    return v
            logger.error(f"atlas_upload_media: URL topilmadi! Tekshirilgan fieldlar: {checked}")
            logger.error(f"atlas_upload_media: To'liq resp={resp}")
            return ""


# ════════════════════════════════════════════════════
#  ATLASCLOUD ASSET LIBRARY
#  console.atlascloud.ai/api/v1/sd/assets
#  Rasmni bir marta yuklab, keyingi generatsiyalarda
#  asset://<atlas_asset_id> sifatida qayta ishlatish
# ════════════════════════════════════════════════════
ATLASCLOUD_CONSOLE_BASE = "https://console.atlascloud.ai"

# In-memory cache: sha256(image_bytes) → "asset-2026xxx..." (atlas_asset_id)
_asset_id_cache: dict = {}


async def atlas_create_asset(image_url: str, name: str = "ref") -> dict:
    """AtlasCloud Asset Library ga rasm yuklaydi.

    Returns: {"db_id": int, "atlas_asset_id": str, "status": str}
    """
    url = f"{ATLASCLOUD_CONSOLE_BASE}/api/v1/sd/assets"
    headers = {"Authorization": f"Bearer {ATLASCLOUD_API_KEY}",
               "Content-Type": "application/json"}
    payload = {"url": image_url, "name": name[:64]}
    async with aiohttp.ClientSession() as s:
        async with s.post(url, json=payload, headers=headers,
                          timeout=aiohttp.ClientTimeout(total=30)) as r:
            resp = await r.json()
            logger.info(f"atlas_create_asset resp: {resp}")
            d = resp.get("data") or {}
            return {
                "db_id":         d.get("id"),
                "atlas_asset_id": d.get("atlas_asset_id", ""),
                "status":        d.get("status", ""),
            }


async def atlas_wait_asset(db_id: int, max_wait: int = 60) -> str:
    """Asset Active bo'lguncha polling qiladi.

    Returns: atlas_asset_id (str) yoki "" (xato/vaqt tugagan)
    """
    url = f"{ATLASCLOUD_CONSOLE_BASE}/api/v1/sd/assets/{db_id}"
    headers = {"Authorization": f"Bearer {ATLASCLOUD_API_KEY}"}
    deadline = asyncio.get_event_loop().time() + max_wait
    async with aiohttp.ClientSession() as s:
        while asyncio.get_event_loop().time() < deadline:
            async with s.get(url, headers=headers,
                             timeout=aiohttp.ClientTimeout(total=15)) as r:
                resp = await r.json()
                d = (resp.get("data") or {})
                status = d.get("status", "")
                aid    = d.get("atlas_asset_id", "")
                logger.info(f"atlas_wait_asset db_id={db_id} status={status}")
                if status == "Active" and aid:
                    return aid
                if status == "Failed":
                    logger.error(f"atlas_wait_asset Failed: {d.get('error_message','')}")
                    return ""
            await asyncio.sleep(3)
    logger.warning(f"atlas_wait_asset timeout (db_id={db_id})")
    return ""


async def atlas_get_or_create_asset(image_url: str, image_bytes: bytes = None,
                                    name: str = "ref") -> str:
    """CDN URL dan asset yaratadi va atlas_asset_id qaytaradi.

    Cache ishlatadi — bir xil rasm ikkinchi marta yuklanmaydi.
    Returns: "asset://<atlas_asset_id>" yoki "" (muvaffaqiyatsiz)
    """
    # Hash asosida cache tekshiruvi
    import hashlib
    _key = hashlib.sha256((image_url or "").encode()).hexdigest()[:16]
    if _key in _asset_id_cache:
        cached = _asset_id_cache[_key]
        logger.info(f"atlas_get_or_create_asset: cache hit → {cached}")
        return f"asset://{cached}"
    try:
        result = await atlas_create_asset(image_url, name=name)
        db_id  = result.get("db_id")
        status = result.get("status", "")
        aid    = result.get("atlas_asset_id", "")
        if not db_id:
            logger.warning(f"atlas_get_or_create_asset: db_id yo'q: {result}")
            return ""
        if status == "Active" and aid:
            _asset_id_cache[_key] = aid
            return f"asset://{aid}"
        # Processing — wait
        aid = await atlas_wait_asset(db_id, max_wait=60)
        if aid:
            _asset_id_cache[_key] = aid
            return f"asset://{aid}"
        return ""
    except Exception as e:
        logger.warning(f"atlas_get_or_create_asset xato: {e}")
        return ""


def _extract_verbatim_speech(idea: str):
    """Ideadan gapirilishi kerak bo'lgan aniq so'zlarni ajratib oladi.

    Returns (idea_clean, speech_text | None)
    Misol: «Salom dunyo» deb gapirsin → ('deb gapirsin', 'Salom dunyo')

    MUHIM: O'zbekcha apostrof (o', g', bo', ko') so'z ichidagi harf —
    ular iqtibos emas, shuning uchun 'single quotes' patternini ISHLATMAYMIZ.
    """
    import re
    # Faqat haqiqiy iqtibos belgilarini qidiradi (guillemet va curly quotes)
    # 'single quotes' pattern OLIB TASHLANDI — Uzbek apostrof (o', g', bo') false positive beradi
    patterns = [
        r'[«""](.+?)[»""]',   # «...» yoki "..." yoki "..."
        r'"(.+?)"',            # standart "..."
    ]
    for pat in patterns:
        m = re.search(pat, idea, re.DOTALL)
        if m and len(m.group(1).strip()) > 1:
            return idea, m.group(1).strip()
    return idea, None


def _prompt_choice_kb(cat_hint: str = "video"):
    """User g'oya yozgach: Yaxshilash / Davom etish tanlovi (A variant — Mini App bilan bir xil)."""
    return InlineKeyboardMarkup([
        [InlineKeyboardButton(T("btn_enhance_idea"), callback_data="prompt:enhance")],
        [InlineKeyboardButton(T("btn_continue_raw"), callback_data="prompt:raw")],
        [InlineKeyboardButton(T("how_write_prompt"), callback_data=f"prompt_tips:{cat_hint}")],
    ])


async def _show_prompt_choice(msg_or_status, context, mid, model_name, res, dur, cost, edit=False):
    """Enhance chaqirmasdan, avval Yaxshilash/Davom tanlovini ko'rsatadi.
    original_idea allaqachon context.user_data da bo'lishi kerak."""
    idea = context.user_data.get("original_idea", "")
    preview = idea[:280] + ("…" if len(idea) > 280 else "")
    model_line = f"🤖 {model_name}" + (f"  |  🖥 {res}  |  ⏱ {dur}s" if is_video(mid) else "")
    cat_hint = "video" if is_video(mid) else "image"
    txt = T("prompt_choice_hdr", v0=(preview), v1=(model_line), v2=(cost))
    kb = _prompt_choice_kb(cat_hint)
    if edit:
        await msg_or_status.edit_text(txt, parse_mode="HTML", reply_markup=kb)
    else:
        await msg_or_status.reply_text(txt, parse_mode="HTML", reply_markup=kb)


async def claude_enhance_prompt(idea: str, model_name: str, cat: str,
                                asp: str = "16:9", res: str = None,
                                dur: int = None, ref_urls: list = None,
                                ref_base64s: list = None,
                                at_tag_refs: bool = False,
                                old_prompt: str = None,
                                model_id: str = "") -> str:
    """Claude API orqali professional prompt yaratadi. API key yo'q bo'lsa DeepSeek-ga o'tadi.

    at_tag_refs=True: Seedance r2v kabi @image1/@video1/@audio1 tag ishlatadigan modellar uchun.
    Bu holda promptda personaj ko'rinishi TAVSIFLANMAYDI — faqat harakat/sahna/kamera.
    old_prompt: Qayta yaratish (retry) rejimi — mavjud promptni foydalanuvchi fikri asosida yaxshilash.
    """
    if not ANTHROPIC_API_KEY:
        if old_prompt:
            # Fallback: DeepSeek ga eski prompt + feedback yuboring
            combined = f"Improve this prompt: '{old_prompt}'. Changes needed: {idea}"
            return await enhance_prompt_with_llm(combined, model_name, cat)
        return await enhance_prompt_with_llm(idea, model_name, cat)

    headers = {
        "x-api-key": ANTHROPIC_API_KEY,
        "anthropic-version": "2023-06-01",
        "content-type": "application/json"
    }
    settings = f"Model: {model_name}, Aspect: {asp}"
    if res:  settings += f", Resolution: {res}"
    if dur:  settings += f", Duration: {dur}s"

    # ── RETRY/FEEDBACK MODE: mavjud promptni yaxshilaymiz ──
    is_seedance_retry = "seedance" in model_id.lower()
    if old_prompt:
        retry_system = (
            f"You are an AI {cat} prompt editor. "
            f"Improve an existing prompt based on user feedback. "
            f"Settings: {settings}.\n"
            f"Rules:\n"
            f"1. Apply ONLY the exact changes the user requests — do not touch unrelated parts.\n"
            f"2. Keep all elements the user did NOT ask to change.\n"
            f"3. User's feedback is the instruction — follow it literally, don't interpret or expand beyond it.\n"
            f"4. Keep under 150 words.\n"
            f"5. Respond with ONLY the improved English prompt — no explanations, no markdown, no prefix."
        )
        retry_content = (
            f"Existing prompt:\n{old_prompt}\n\n"
            f"User feedback (what to change/improve — may be in Uzbek, Russian, or English):\n{idea}\n\n"
            f"Return the improved prompt:"
        )
        retry_payload = {
            "model": CLAUDE_MODEL,
            "max_tokens": 400,
            "system": retry_system,
            "messages": [{"role": "user", "content": retry_content}]
        }
        try:
            async with aiohttp.ClientSession() as s:
                async with s.post("https://api.anthropic.com/v1/messages",
                                  json=retry_payload, headers=headers,
                                  timeout=aiohttp.ClientTimeout(total=25)) as r:
                    resp = await r.json()
                    if "content" in resp:
                        raw = resp["content"][0]["text"].strip()
                        lines = raw.split('\n')
                        while lines and (lines[0].lstrip().startswith('#') or lines[0].strip() == ''):
                            lines.pop(0)
                        cleaned = '\n'.join(lines).strip()
                        return cleaned if cleaned else raw
                    logger.warning(f"claude_enhance retry response: {resp}")
        except Exception as e:
            logger.warning(f"claude_enhance_prompt retry xato: {e}")
        return old_prompt   # fallback: eski promptni qaytaramiz

    # Aniq gapirilishi kerak bo'lgan so'zlarni ajratib olamiz
    idea, speech_text = _extract_verbatim_speech(idea)

    headers = {
        "x-api-key": ANTHROPIC_API_KEY,
        "anthropic-version": "2023-06-01",
        "content-type": "application/json"
    }
    settings = f"Model: {model_name}, Aspect: {asp}"
    if res:  settings += f", Resolution: {res}"
    if dur:  settings += f", Duration: {dur}s"

    # Ustuvorlik: ref_base64s (to'g'ridan-to'g'ri bytes, CDN kerak emas) → ref_urls (CDN yuklab olish)
    has_refs = bool(ref_base64s) or bool(ref_urls)

    # Seedance modellari uchun maxsus prompt engineering
    is_seedance = "seedance" in model_id.lower()

    # Aniq so'z bo'lsa — verbatim qoida system promptga qo'shiladi
    verbatim_rule = ""
    if speech_text:
        verbatim_rule = (
            f"\nCRITICAL — VERBATIM SPEECH: The character must say EXACTLY these words: \"{speech_text}\"\n"
            f"Include in the prompt as: the character says: \"{speech_text}\"\n"
            f"DO NOT translate, paraphrase, shorten, or change these words in ANY way. "
            f"Copy them character-by-character into the output prompt.\n"
        )

    # ══════════════════════════════════════════════════════════════════
    # UNIVERSAL CORE RULE injected into every system prompt:
    # The user's idea is the PRIMARY content. Stay faithful to it.
    # ══════════════════════════════════════════════════════════════════
    universal_core = (
        f"GOLDEN RULE — USER'S IDEA IS EVERYTHING:\n"
        f"• Every element the user mentioned MUST appear in the output, word-for-word faithfully.\n"
        f"• ONLY add details that EXPAND what the user already described (make it more specific, not different).\n"
        f"• NEVER add random cinematic flourishes, camera movements, or style terms the user did NOT request.\n"
        f"• If the user said 'man eating pizza', do NOT add 'dramatic lighting', 'lens flare', or 'cinematic tracking shot' — add only what makes 'man eating pizza' clearer and more detailed.\n"
        f"• If the user mentioned a specific style (cinematic, dark, funny, etc.) — use it. If not — don't invent one.\n"
        f"• The output should feel like the user's idea expanded, NOT replaced by AI-generated fluff.\n"
    )

    if at_tag_refs and has_refs:
        # Seedance reference-to-video va shunga o'xshash @tag modellar uchun maxsus system:
        # Personajning tashqi ko'rinishini TASVIRLAMASLIK kerak — bu reference rasm vazifasi.
        # Lekin rasmdan sahna/muhit/yorug'lik/kayfiyat ma'lumotlari OLINADI va boyitiladi.
        if is_seedance:
            system = (
                f"You are an AI {cat} prompt writer for Seedance reference-based video models. "
                f"Settings: {settings}.\n"
                f"{universal_core}"
                f"SEEDANCE STYLE GUIDE (how this model reads prompts):\n"
                f"- Seedance reads the FIRST 20-30 words most heavily — they lock the subject and core action. Put WHO/WHAT + the main action at the very start.\n"
                f"- Structure order: Subject + Action + Environment + Camera + Lighting + Style. Style/lighting come AFTER the subject is anchored, never before.\n"
                f"- Camera movement is critical: always specify it (e.g. dolly, pan, tracking shot, slow push-in, orbit). Without it, Seedance produces flat, minimal motion.\n"
                f"- Prefer clear directive descriptions over stacking adjectives ('walks slowly with hands in pockets' beats 'beautiful cinematic walk').\n"
                f"- Target 50-100 words total.\n"
                f"- Use common words; avoid rare characters or special symbols.\n"
                f"- With references: text should build the ENVIRONMENT and action; let the reference image/video carry character and motion — do not over-describe in text.\n"
                f"You have reference image(s) showing the character. Analyze them to understand:\n"
                f"  • The scene/location visible in the image\n"
                f"  • Background elements, props, lighting already present\n"
                f"  • Character's current posture/pose (NOT appearance)\n"
                f"OUTPUT RULES:\n"
                f"1. Reference tagging — use LOWERCASE tags to refer to uploaded references:\n"
                f"   • Images  → @image1, @image2, @image3 … (up to 9 images)\n"
                f"   • Videos  → @video1, @video2, @video3 … (up to 3 video clips)\n"
                f"   • Audio   → @audio1, @audio2 … (up to 3 audio clips)\n"
                f"   Start the prompt with the relevant @tag (e.g. '@image1'). "
                f"NEVER describe face/hair/skin/clothing/body of any referenced character.\n"
                f"2. The user's requested action/scene is the CORE — write it first and clearly.\n"
                f"3. Add environment details from the image only if consistent with the user's request.\n"
                f"4. Add camera/lighting hints ONLY if the user mentioned them OR if they are directly implied.\n"
                f"5. LIP SYNC: add 'natural lip sync' ONLY if user explicitly mentions speaking/talking/gapirsin/aytsin/says/dialog/quoted words. "
                f"Laughing, crying, shouting = NO lip sync.\n"
                f"{verbatim_rule}"
                f"Keep under 120 words. Output ONLY the English prompt — no analysis, no explanations."
            )
        else:
            system = (
                f"You are an AI {cat} prompt writer for reference-based video/image models. "
                f"Settings: {settings}.\n"
                f"{universal_core}"
                f"You have reference image(s). Use them to understand the scene context — "
                f"but NEVER describe the character's face, hair, skin, clothing, or body.\n"
                f"OUTPUT RULES:\n"
                f"1. Refer to character ONLY as '@image1' (lowercase).\n"
                f"2. User's action/scene request is the CORE — write it faithfully first.\n"
                f"3. Enrich ONLY with scene/environment from the image if consistent with user's idea.\n"
                f"4. LIP SYNC: ONLY if user explicitly says speaking/talking/gapirsin/aytsin/says/dialog/quoted words. "
                f"Laughing, crying, shouting = NO lip sync.\n"
                f"{verbatim_rule}"
                f"Keep under 100 words. Output ONLY the English prompt — no explanations, no markdown."
            )
    else:
        if is_seedance:
            system = (
                f"You are an AI {cat} prompt writer for Seedance video models. "
                f"Translate the user's idea (Uzbek, Russian, or English) into English "
                f"and expand it for Seedance — while staying true to what the user asked for. "
                f"Settings: {settings}.\n"
                f"{universal_core}"
                f"SEEDANCE STYLE GUIDE (how this model reads prompts):\n"
                f"- Seedance reads the FIRST 20-30 words most heavily — they lock the subject and core action. Put WHO/WHAT + the main action at the very start.\n"
                f"- Structure order: Subject + Action + Environment + Camera + Lighting + Style. Style/lighting come AFTER the subject is anchored, never before.\n"
                f"- Camera movement is critical: always specify it (e.g. dolly, pan, tracking shot, slow push-in, orbit). Without it, Seedance produces flat, minimal motion.\n"
                f"- Prefer clear directive descriptions over stacking adjectives ('walks slowly with hands in pockets' beats 'beautiful cinematic walk').\n"
                f"- Target 50-100 words total.\n"
                f"- Use common words; avoid rare characters or special symbols.\n"
                f"SEEDANCE EXPANSION GUIDE (only add what's missing from user's idea):\n"
                f"- Subject details: if user described a person vaguely, add appearance details (age, clothing, expression)\n"
                f"- Action precision: make the action more specific (not 'walks' but 'walks slowly with hands in pockets')\n"
                f"- Scene/environment: if user mentioned a place, add environment details consistent with it\n"
                f"- Camera/lighting: add ONLY if user mentioned them OR if the action clearly requires it (e.g. close-up for face, wide for running)\n"
                f"RULES:\n"
                f"- If the user's idea is already detailed — translate faithfully with minimal additions.\n"
                f"- Physical action scenes: mention shot type (full body, wide) only if needed to show the action.\n"
                f"- LIP SYNC: ONLY if user explicitly mentions speaking/talking/gapirsin/aytsin/says/dialog or quotes words. "
                f"Add 'natural lip sync'. DO NOT add for laughing, crying, or non-speech.\n"
                f"{verbatim_rule}"
                f"Keep under 130 words. Output ONLY the English prompt — no explanations, no markdown, no prefix."
            )
        else:
            system = (
                f"You are an AI {cat} prompt writer. "
                f"Translate the user's idea (Uzbek, Russian, or English) into English "
                f"and expand it into a clear generation prompt — while staying true to what the user asked. "
                f"Settings: {settings}.\n"
                f"{universal_core}"
                f"EXPANSION GUIDE (add only what's missing):\n"
                f"- Make vague elements more specific (who, what, where, how)\n"
                f"- If action involves movement: specify it precisely\n"
                f"- Add shot type/composition ONLY if needed (full body for action, close-up for face)\n"
                f"- Add lighting/style ONLY if user mentioned or implied it\n"
                f"LIP SYNC: ONLY if user explicitly mentions speaking/talking/gapirsin/aytsin/says/dialog. "
                f"Add 'natural lip sync'. DO NOT add for laughing/crying/expressions/non-speech.\n"
                f"{verbatim_rule}"
                f"Keep under 130 words. Output ONLY the English prompt — no explanations."
            )

    if has_refs:
        content = []
        if ref_base64s:
            logger.info(f"claude_enhance: {len(ref_base64s)} ref rasm base64 dan ishlatilmoqda (CDN yuklab olish kerak emas)")
            for img_b64 in ref_base64s[:3]:
                # Base64 decoded bytes dan MIME aniqlaymiz
                try:
                    raw = base64.b64decode(img_b64[:20])
                    if raw[:3] == b'\xff\xd8\xff':   mime = "image/jpeg"
                    elif raw[:8] == b'\x89PNG\r\n\x1a\n': mime = "image/png"
                    elif raw[:6] in (b'GIF87a', b'GIF89a'): mime = "image/gif"
                    else: mime = "image/jpeg"
                except Exception: mime = "image/jpeg"
                content.append({"type": "image", "source": {"type": "base64", "media_type": mime, "data": img_b64}})
                logger.info(f"claude_enhance: base64 rasm OK ({mime})")
        elif ref_urls:
            logger.info(f"claude_enhance: {len(ref_urls)} ref URL CDN dan yuklanmoqda...")
            async with aiohttp.ClientSession() as dl_session:
                for url in ref_urls[:3]:
                    try:
                        async with dl_session.get(url, timeout=aiohttp.ClientTimeout(total=10)) as r:
                            img_bytes = await r.read()
                        img_b64 = base64.b64encode(img_bytes).decode()
                        if img_bytes[:3] == b'\xff\xd8\xff':   mime = "image/jpeg"
                        elif img_bytes[:8] == b'\x89PNG\r\n\x1a\n': mime = "image/png"
                        elif img_bytes[:6] in (b'GIF87a', b'GIF89a'): mime = "image/gif"
                        else: mime = "image/jpeg"
                        content.append({"type": "image", "source": {"type": "base64", "media_type": mime, "data": img_b64}})
                        logger.info(f"claude_enhance: CDN rasm OK ({mime}, {len(img_bytes)} bayt)")
                    except Exception as img_err:
                        logger.warning(f"ref image CDN download xato ({url}): {img_err}")

        if at_tag_refs:
            # @tag modellar: rasmni tahlil qilib, harakat + sahna + kamera boyitiladi
            content.append({"type": "text",
                            "text": (
                                f"Reference image(s) above show the character. Look at them carefully.\n\n"
                                f"From the image(s), identify (do NOT include this analysis in output):\n"
                                f"- What is the scene/location? (studio, outdoor, street, room, etc.)\n"
                                f"- What objects, props, or background elements are visible?\n"
                                f"- What is the lighting like? (natural, artificial, direction, warmth)\n"
                                f"- What mood/atmosphere does the image have?\n"
                                f"- What is the character's current body position/posture?\n\n"
                                f"User's request (may be Uzbek, Russian, or English): \"{idea}\"\n\n"
                                f"Now write the video generation prompt:\n"
                                f"- Start with '@image1' (the character, lowercase)\n"
                                f"- Describe the ACTION the user requested in precise detail\n"
                                f"- Describe the ENVIRONMENT using what you saw in the image, enriched by the user's idea\n"
                                f"- Add CAMERA angle/movement and LIGHTING consistent with the image\n"
                                f"- Do NOT mention the character's face, hair, clothing, skin or body at all\n"
                                f"Output the prompt only — no analysis, no explanation."
                            )})
        else:
            # Oddiy reference: harakatni BIRINCHI o'rinda, ko'rinishni IKKINCHI o'rinda saqlash
            content.append({"type": "text",
                            "text": (
                                f"User's idea: \"{idea}\"\n\n"
                                f"CRITICAL PRIORITY ORDER:\n"
                                f"1. PRIMARY — the user's requested ACTION/SCENE: \"{idea}\" — this MUST be the core of the prompt. Never ignore or replace it.\n"
                                f"2. SECONDARY — describe the character's appearance (face, hair, clothing, style) from the reference image above.\n\n"
                                f"Combine both: [character appearance from reference] doing/in [user's requested scene/action].\n"
                                f"The scene/action from the user's idea takes priority. Do NOT replace it with a simple portrait or standing pose.\n\n"
                                f"COMPOSITION RULE: If the idea involves physical action (flying, running, jumping, dancing, fighting, etc.) — "
                                f"use 'full body shot', 'wide angle', 'entire body visible' in the prompt so the character's body and action are fully shown. "
                                f"Avoid close-up or headshot framing for action scenes."
                            )})
    else:
        content = f"Idea: {idea}"

    payload = {
        "model": CLAUDE_MODEL,
        "max_tokens": 400,
        "system": system,
        "messages": [{"role": "user", "content": content}]
    }
    try:
        async with aiohttp.ClientSession() as s:
            async with s.post("https://api.anthropic.com/v1/messages",
                              json=payload, headers=headers,
                              timeout=aiohttp.ClientTimeout(total=25)) as r:
                resp = await r.json()
                if "content" in resp:
                    raw = resp["content"][0]["text"].strip()
                    # Markdown header larni olib tashlaymiz
                    # (masalan "# Video Generation Prompt\n\n" kabi Claude qo'shadigan narsalar)
                    lines = raw.split('\n')
                    while lines and (lines[0].lstrip().startswith('#') or lines[0].strip() == ''):
                        lines.pop(0)
                    cleaned = '\n'.join(lines).strip()
                    return cleaned if cleaned else raw
                logger.warning(f"claude_enhance response: {resp}")
    except Exception as e:
        logger.warning(f"claude_enhance_prompt xato: {e}")
    return await enhance_prompt_with_llm(idea, model_name, cat)   # fallback


async def claude_assistant_chat(history: list, system: str) -> str:
    """Claude bilan ko'p qavatli suhbat — prompt takomillashtirish uchun."""
    headers = {
        "x-api-key": ANTHROPIC_API_KEY,
        "anthropic-version": "2023-06-01",
        "content-type": "application/json"
    }
    payload = {
        "model": CLAUDE_MODEL,
        "max_tokens": 700,
        "system": system,
        "messages": history
    }
    async with aiohttp.ClientSession() as s:
        async with s.post("https://api.anthropic.com/v1/messages",
                          json=payload, headers=headers,
                          timeout=aiohttp.ClientTimeout(total=30)) as r:
            resp = await r.json()
            if "content" in resp:
                return resp["content"][0]["text"].strip()
            raise Exception(f"Claude API xato: {resp.get('error', resp)}")


async def aqlbek_analyze_ref_image(img_bytes: bytes, mime: str = "image/jpeg",
                                   ref_index: int = 1, total: int = 1) -> str:
    """Referens rasmni Aqlbek orqali tahlil qiladi — ob'ektlarni tasvirlab video g'oyasini so'raydi."""
    if not ANTHROPIC_API_KEY:
        return ""
    try:
        b64 = base64.b64encode(img_bytes).decode()
        headers = {
            "x-api-key": ANTHROPIC_API_KEY,
            "anthropic-version": "2023-06-01",
            "content-type": "application/json",
        }
        ref_note = f" ({ref_index}/{total}-rasm)" if total > 1 else ""
        payload = {
            "model": CLAUDE_MODEL,
            "max_tokens": 350,
            "system": (
                "Sen Aqlbek — Voro Creator botining do'stona AI yordamchisisiz. "
                "O'zbek tilini a'lo darajada tushunasan va faqat O'ZBEK TILIDA gaplashan. "
                "Foydalanuvchi video uchun reference rasm yubordi. "
                "Quyidagilarni qil:\n"
                "1) Rasmda nimalar ko'rinishini QISQACHA tasvirla (1-2 jumla): "
                "   ob'ektlar, odamlar, joylar, ranglar, kayfiyat.\n"
                "2) Bu rasmni reference sifatida ishlatish mumkinligini ayt.\n"
                "3) Foydalanuvchidan bu reference bilan qanday VIDEO yaratmoqchi ekanini so'ra — "
                "   ilhomlantiruvchi, samimiy tarzda. Oddiy, tushunarli so'zlar ishlat.\n"
                "Jami 3-4 jumladan oshmaydi. Emoji ishlat — do'stona bo'l!"
                + _llm_lang_note()
            ),
            "messages": [
                {
                    "role": "user",
                    "content": [
                        {
                            "type": "image",
                            "source": {"type": "base64", "media_type": mime, "data": b64}
                        },
                        {"type": "text",
                         "text": f"Bu reference rasmni{ref_note} tahlil qil va video g'oyasini so'ra."}
                    ]
                }
            ]
        }
        async with aiohttp.ClientSession() as s:
            async with s.post("https://api.anthropic.com/v1/messages",
                              json=payload, headers=headers,
                              timeout=aiohttp.ClientTimeout(total=20)) as r:
                resp = await r.json()
                if "content" in resp:
                    return resp["content"][0]["text"].strip()
        return ""
    except Exception as e:
        logger.warning(f"aqlbek_analyze_ref_image xato: {e}")
        return ""


async def aqlbek_send_ref_greeting(bot, chat_id: int, context):
    """Endi ref_text ichida maslahat ko'rsatiladi — alohida xabar kerak emas."""
    return


async def aqlbek_ref_text_chat(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """UPLOAD_REF holatida foydalanuvchi yozgan matn — ref_text ma'lumotini qayta ko'rsatadi.
    AI maslahat yo'q, faqat reference biriktirish haqida oddiy yo'riqnoma.
    """
    mid  = context.user_data.get("model_id", "")
    meta = MODEL_META.get(mid, {})
    user_text = (update.message.text or "").strip()

    # video_clip_ref modellar: URL yozilsa → video_clip_url sifatida saqlash
    if meta.get("video_clip_ref") and user_text.startswith(("http://", "https://")):
        context.user_data["video_clip_url"] = user_text
        n_img = len(context.user_data.get("ref_urls", []))
        n_aud = len(context.user_data.get("ref_audio_urls", []))
        n_vid = len(context.user_data.get("ref_video_clip_urls", []))
        req   = meta.get("refs_req", False)
        mx    = meta.get("refs", 1)
        await update.message.reply_text(
            ref_text(mid, n_img, n_aud, n_vid, video_clip_url=user_text),
            parse_mode="HTML",
            reply_markup=ref_kb(n_img, mx, req, mid, n_aud, n_vid))
        return UPLOAD_REF

    # video_ref + skip_all_steps (masalan Kling O3): URL yozilsa → ref_video_url sifatida saqlash
    if meta.get("video_ref") and meta.get("skip_all_steps") and user_text.startswith(("http://", "https://")):
        context.user_data["ref_video_url"] = user_text
        context.user_data["ref_urls"]    = []
        context.user_data["ref_base64s"] = []
        context.user_data["refs_count"]  = 0
        max_imgs_v = meta.get("refs", 4)
        _offer_url_kb = InlineKeyboardMarkup([[
            InlineKeyboardButton(T("add_ref_image"), callback_data="ref:stay"),
            InlineKeyboardButton(T("continue_btn"), callback_data="ref:ok"),
        ]])
        await update.message.reply_text(
            T("fs37", v0=(max_imgs_v)),
            parse_mode="HTML", reply_markup=_offer_url_kb)
        return UPLOAD_REF

    # Har qanday boshqa matn → ref_text ma'lumotini qayta ko'rsat
    n_img = len(context.user_data.get("ref_urls", []))
    n_aud = len(context.user_data.get("ref_audio_urls", []))
    n_vid = len(context.user_data.get("ref_video_clip_urls", []))
    req   = meta.get("refs_req", False)
    mx    = meta.get("refs", 1)
    await update.message.reply_text(
        ref_text(mid, n_img, n_aud, n_vid), parse_mode="HTML",
        reply_markup=ref_kb(n_img, mx, req, mid, n_aud, n_vid))
    return UPLOAD_REF


def _bot_prompt_profile(model_name: str) -> str:
    """Model nomidan uning 'prompt tili'ni aniqlaydi."""
    n = (model_name or "").lower()
    if "seedance" in n:
        return ("This model uses reference tags: bind media with @image1/@audio1/@video1 in upload order; "
                "never describe a tagged subject's face in words. Structure: subject+tags -> action verbs -> "
                "camera -> environment/lighting -> mood.")
    if "gemini" in n:
        return ("Write a flowing CINEMATIC NARRATIVE paragraph like a director. No @tags — say 'the person "
                "from the reference image' and describe them precisely. This model generates native AUDIO: "
                "include ambient sound/SFX and any dialogue in double quotes with the speaker named. "
                "Specify camera movement and lighting.")
    if "veo" in n:
        return ("Concise precise prompt: one subject, one action, explicit camera term, lighting. "
                "Dialogue in double quotes generates speech. No @tags.")
    if "kling" in n:
        return ("Lead with strong MOTION verbs and physical detail. Describe the first frame (the uploaded "
                "image), then the unfolding motion, then camera movement. No @tags.")
    if "banana" in n or "seedream" in n:
        return ("EDITING model: write an imperative instruction — Add/Remove/Replace/Change X while keeping "
                "composition, identity, lighting and background unchanged. Name exactly what changes and what stays.")
    if "gpt" in n:
        return ("Detailed scene in full sentences; any text to render in the image goes in double quotes "
                "with placement.")
    if "hailuo" in n or "wan" in n or "grok" in n or "happyhorse" in n or "vidu" in n:
        return "Vivid subject-action-camera description with concrete nouns and colors. No @tags."
    if "infinitetalk" in n or "lipsync" in n:
        return ("Lipsync: describe the speaker's emotional delivery, head/eye behavior and framing. "
                "Audio carries the words — do not write dialogue text.")
    return "Clear professional prompt: subject, action, camera, lighting, style. No @tags."

_LANG_GENIUS = ("LANGUAGE INTELLIGENCE: the user may write in Uzbek (Latin or Cyrillic, ANY dialect), "
    "Russian, English, or a MIX, with typos, slang, missing apostrophes (korish=ko'rish) and phonetic "
    "spellings. Confidently infer the TRUE intent - never take a typo literally when context shows otherwise. ")

async def enhance_prompt_with_llm(idea: str, model_name: str, cat: str) -> str:
    """Foydalanuvchi g'oyasini professional AI promptga aylantiradi (AtlasCloud deepseek-v3)."""
    url = "https://api.atlascloud.ai/v1/chat/completions"
    headers = {"Authorization": f"Bearer {ATLASCLOUD_API_KEY}", "Content-Type": "application/json"}
    _, speech_text = _extract_verbatim_speech(idea)
    verbatim_rule = ""
    if speech_text:
        verbatim_rule = (
            f"CRITICAL — VERBATIM SPEECH: The character must say EXACTLY: \"{speech_text}\". "
            f"Include as: the character says: \"{speech_text}\". "
            f"DO NOT translate, paraphrase, or change these words. Copy them exactly. "
        )
    system = (
        f"You are an AI {cat} prompt writer. "
        f"MODEL-SPECIFIC STYLE (follow strictly): {_bot_prompt_profile(model_name)} "
        f"{_LANG_GENIUS}"
        "Translate the user's idea (Uzbek, Russian, or English) into English "
        "and expand it into a generation prompt — while staying true to what the user asked. "
        "GOLDEN RULE: The user's idea is the PRIMARY content. "
        "Every element the user mentioned MUST appear in the output. "
        "Only ADD details that expand what the user described — never replace or bury it under generic terms. "
        "Do NOT add random cinematic flourishes, camera movements, or style terms the user did not request. "
        "If the user said something simple, keep it simple but clear. "
        "If the action involves movement: make it more precise. "
        "Add shot type ONLY if needed to show the action. "
        "LIP SYNC: ONLY if user explicitly mentions speaking/talking/gapirsin/aytsin/says/dialog. "
        "Add 'natural lip sync'. DO NOT add for laughing/crying/non-speech. "
        f"{verbatim_rule}"
        "Keep under 150 words. "
        "Respond with ONLY the English prompt — no explanations, no extra text."
    )
    payload = {
        "model": "deepseek-ai/deepseek-v4-flash",
        "messages": [
            {"role": "system", "content": system},
            {"role": "user", "content": f"Model: {model_name}\nIdea: {idea}"}
        ],
        "max_tokens": 300,
        "temperature": 0.7
    }
    try:
        async with aiohttp.ClientSession() as s:
            async with s.post(url, json=payload, headers=headers, timeout=aiohttp.ClientTimeout(total=20)) as r:
                resp = await r.json()
                logger.info(f"LLM raw response keys: {list(resp.keys())}")
                # Handle both standard OpenAI format and AtlasCloud wrapper formats
                if "choices" in resp:
                    enhanced = resp["choices"][0]["message"]["content"].strip()
                elif "data" in resp and isinstance(resp["data"], dict) and "choices" in resp["data"]:
                    enhanced = resp["data"]["choices"][0]["message"]["content"].strip()
                elif "data" in resp and isinstance(resp["data"], str):
                    enhanced = resp["data"].strip()
                elif "content" in resp:
                    enhanced = resp["content"].strip()
                elif "message" in resp:
                    enhanced = resp["message"].strip()
                else:
                    logger.warning(f"LLM unknown response format: {str(resp)[:200]}")
                    return idea
                logger.info(f"LLM enhanced prompt: {enhanced[:120]}…")
                return enhanced
    except Exception as e:
        logger.warning(f"enhance_prompt_with_llm xato: {e} — original idea ishlatiladi")
        return idea  # Xato bo'lsa original g'oyani qaytaramiz


async def atlas_submit(*args, **kwargs):
    """Atlas submit — 504/502/timeout bo'lsa avtomatik qayta urinadi (Cloudflare himoyasi)."""
    last = None
    for _i in range(3):
        try:
            return await _atlas_submit_inner(*args, **kwargs)
        except Exception as _e:
            _m = str(_e).lower()
            _retriable = any(k in _m for k in ("504", "502", "503", "timeout", "timed out",
                                               "gateway", "mimetype", "text/html",
                                               "connection reset", "server disconnected"))
            last = _e
            if not _retriable or _i == 2:
                raise
            logger.warning(f"atlas_submit retry {_i+1}/2 ({_e})")
            await asyncio.sleep(7 + _i * 8)
    raise last


async def _atlas_submit_inner(model_id, prompt, aspect_ratio, resolution=None, duration=None,
                       image_url=None, image_urls: list = None, video_url: str = None,
                       audio_urls: list = None, video_clip_urls: list = None,
                       video_clip_url: str = None,
                       skip_audio: bool = False,
                       extra_params: dict = None):
    """AtlasCloud generateVideo/generateImage API ga so'rov yuboradi.

    audio_urls       -- multi-ref modellar uchun audio URL list (Seedance r2v)
    video_clip_urls  -- multi-ref modellar uchun video klip URL list (Seedance r2v)
    skip_audio       -- True bo'lsa generate_audio payload'ga qo'shilmaydi
                        (ByteDance "sensitive audio" xatosidan keyin qayta urinishda ishlatiladi)
    """
    endpoint = "generateVideo" if is_video(model_id) else "generateImage"
    url = f"{ATLASCLOUD_BASE}/api/v1/model/{endpoint}"
    headers = {"Authorization": f"Bearer {ATLASCLOUD_API_KEY}", "Content-Type": "application/json"}
    is_veo = "veo3" in model_id
    meta  = MODEL_META.get(model_id, {})
    # Ref bo'lsa boshqa model ID ishlatadigan modellar (masalan seedance-2.0 -> reference-to-video)
    has_refs = bool(image_urls or image_url or audio_urls or video_clip_urls or video_clip_url)
    actual_model_id = meta.get("alt_model_with_ref", model_id) if has_refs else model_id
    # Alt model ga o'tilganda uning meta'sini ishlatamiz (aspect_field, ref_param va boshqalar)
    effective_meta = MODEL_META.get(actual_model_id, meta) if actual_model_id != model_id else meta
    payload = {
        "model":  actual_model_id,
        "prompt": prompt,
    }
    # Aspect ratio field nomi modellarga qarab farq qiladi:
    # META "aspect_field" override bo'lsa uni ishlatamiz (masalan start-end-frame: "aspect_ratio")
    # Aks holda: Veo 3.x -> "aspectRatio", qolganlari -> "aspect_ratio"
    # no_aspect_param: True bo'lsa aspect umuman yuborilmaydi (masalan veo3.1/reference-to-video)
    if aspect_ratio and not effective_meta.get("no_aspect_param"):
        asp_field_override = effective_meta.get("aspect_field")
        if asp_field_override:
            payload[asp_field_override] = aspect_ratio
        elif is_veo:
            payload["aspectRatio"] = aspect_ratio
        else:
            payload[effective_meta.get("aspect_field", "aspect_ratio")] = aspect_ratio
    if resolution and not effective_meta.get("no_resolution_param"):
        # res_api_map: foydalanuvchi "1080p" tanlasa API "1080p-SR" oladi (Seedance Fast kabi)
        _res_api_map = effective_meta.get("res_api_map", {})
        payload["resolution"] = _res_api_map.get(resolution, resolution)
    no_dur_param = effective_meta.get("no_dur_param", False)
    # MUHIM: duration > 0 shart — -1 yoki 0 hech qachon body'ga qo'shilmaydi.
    # Agar -1 yetib kelsa bu _do_generate'dagi mantiq xatosi — assertion tutib qoladi.
    if duration is not None and duration > 0 and not no_dur_param:
        dur_field_override = effective_meta.get("dur_field")
        if dur_field_override:
            payload[dur_field_override] = int(duration)
        elif is_veo:
            payload["durationSeconds"] = int(duration)
        else:
            payload["duration"] = int(duration)
        logger.info(f"atlas_submit: payload duration={int(duration)} "
                    f"model={actual_model_id} field={dur_field_override or ('durationSeconds' if is_veo else 'duration')}")

    # ── Multi-modal reference (Seedance reference-to-video — official API spec) ──
    # Field nomlari: reference_images | reference_videos | reference_audios
    # MUHIM: OpenAPI schema minItems:1 — bo'sh array ([]) yuborish API xatosi!
    # Faqat haqiqiy kontent bo'lganda yuboriladi.
    rp_images = effective_meta.get("ref_param_images")   # "reference_images"
    rp_audios = effective_meta.get("ref_param_audios")   # "reference_audios"
    rp_videos = effective_meta.get("ref_param_videos")   # "reference_videos"
    if rp_images or rp_audios or rp_videos:
        all_img_urls = (image_urls or []) + ([image_url] if image_url else [])
        all_aud_urls = audio_urls or []
        all_vid_urls = video_clip_urls or []
        # minItems:1 — bo'sh array yubormang! Faqat mavjud bo'lsa yuboriladi.
        if rp_images and all_img_urls:
            payload[rp_images] = all_img_urls
        if rp_audios and all_aud_urls:
            payload[rp_audios] = all_aud_urls
        if rp_videos and all_vid_urls:
            payload[rp_videos] = all_vid_urls
        # watermark, return_last_frame — API docs da ko'rsatilgan
        if "watermark" in effective_meta:
            payload["watermark"] = effective_meta["watermark"]
        if "return_last_frame" in effective_meta:
            payload["return_last_frame"] = effective_meta["return_last_frame"]

    else:
        # ── Standard reference handling ──
        ref_field       = effective_meta.get("ref_param", "image_url")
        ref_array_field = effective_meta.get("ref_array_field")  # "images" kabi array field

        # ── last_image_ref: birinchi rasm -> "image", ikkinchi rasm -> "last_image" (yoki second_image_field) ──
        # google/veo3.1-lite/start-end-frame-to-video, kwaivgi/kling-v3.0-std/image-to-video uchun
        if effective_meta.get("last_image_ref"):
            all_frames = []
            if image_urls:
                all_frames.extend(image_urls)
            elif image_url:
                all_frames.append(image_url)
            if len(all_frames) >= 1:
                payload["image"] = all_frames[0]
            if len(all_frames) >= 2:
                _second_field = effective_meta.get("second_image_field", "last_image")
                payload[_second_field] = all_frames[1]

        # InfiniteTalk: "image" (portret rasm) + "audio" (ovoz fayl) + ixtiyoriy "prompt"
        elif effective_meta.get("infinitetalk"):
            _it_imgs = (image_urls or []) + ([image_url] if image_url else [])
            if _it_imgs:
                payload["image"] = _it_imgs[0]
            if audio_urls:
                payload["audio"] = audio_urls[0]
            # Prompt ixtiyoriy — bo'sh bo'lsa yuborilmasin
            if not prompt:
                payload.pop("prompt", None)

        # Motion Control: "image" (string) + "video" (string) + character_orientation (via extra_params)
        elif effective_meta.get("motion_control"):
            if video_url:
                payload["video"] = video_url
            _mc_imgs = (image_urls or []) + ([image_url] if image_url else [])
            if _mc_imgs:
                payload["image"] = _mc_imgs[0]  # single string, not array

        # Kling O3 Video: "video" (required) + "images" (optional array) + keep_original_sound
        elif effective_meta.get("skip_all_steps") and effective_meta.get("video_ref"):
            if video_url:
                payload["video"] = video_url
            _kl_imgs = (image_urls or []) + ([image_url] if image_url else [])
            if _kl_imgs:
                payload["images"] = _kl_imgs
            if not effective_meta.get("no_keep_sound"):
                payload["keep_original_sound"] = True

        # Video reference (video-to-video models)
        elif video_url and meta.get("video_ref"):
            payload["video_url"] = video_url
            payload[ref_field]   = video_url

        # Image reference -- array field ishlaydigan modellar
        elif ref_array_field and image_urls:
            payload[ref_array_field] = image_urls
        elif ref_array_field and image_url:
            payload[ref_array_field] = [image_url]

        # Oddiy image reference
        elif image_urls and len(image_urls) > 1:
            payload[ref_field]    = image_urls[0]
            payload["image_urls"] = image_urls
        elif image_urls and len(image_urls) == 1:
            payload[ref_field] = image_urls[0]
        elif image_url:
            payload[ref_field] = image_url

    # ── video_clip_ref modellar (masalan nano-banana-2/reference-to-image) ──
    # video_clip_url → "video_clips": [{"url":..., "start":0, "ends":0, "fps":1}]
    if video_clip_url and effective_meta.get("video_clip_ref"):
        payload["video_clips"] = [{"url": video_clip_url, "start": 0, "ends": 0, "fps": 1}]
        logger.info(f"atlas_submit: video_clips qo'shildi → {video_clip_url[:80]}")

    # ── audio_ref_field: single audio URL → payload["audio"] = url_string
    #    Wan 2.7 I2V kabi last_image_ref modellar uchun (multi-ref emas)
    _aud_ref_fld = effective_meta.get("audio_ref_field")
    if _aud_ref_fld and audio_urls:
        payload[_aud_ref_fld] = audio_urls[0]
        logger.info(f"atlas_submit: audio_ref_field={_aud_ref_fld} → {audio_urls[0][:60]}")

    # Audio qo'llab-quvvatlaydigan video modellar uchun
    # skip_audio=True: ByteDance "sensitive audio" xatosidan keyin ovozsizsiz qayta urinish
    # audio_urls bor bo'lsa → foydalanuvchi o'z audiosini lipsync uchun yuborgan,
    # shuning uchun generate_audio=True QOSHILMAYDI (yangi audio yaratilmaydi)
    if is_video(model_id) and meta.get("audio") and not skip_audio and not audio_urls:
        _audio_field = effective_meta.get("audio_field", "generate_audio")
        payload[_audio_field] = True

    # extra_payload: model'ga xos har doim qo'shiladigan parametrlar (cfg_scale kabi)
    _extra_p = effective_meta.get("extra_payload", {})
    if _extra_p:
        payload.update(_extra_p)

    # extra_params: generatsiya vaqtida kiritilgan dinamik parametrlar (character_orientation kabi)
    if extra_params:
        payload.update(extra_params)

    img_c   = len(image_urls) if image_urls else (1 if image_url else 0)
    aud_c   = len(audio_urls) if audio_urls else 0
    vclip_c = len(video_clip_urls) if video_clip_urls else 0
    ref_info = ("vid_ref" if video_url
                else f"img={img_c} aud={aud_c} vclip={vclip_c}" if has_refs
                else "no_ref")

    # Debug: to'liq JSON payload ni log qilamiz (reference bo'lsa ayniqsa muhim)
    import json as _json
    logger.info(f"atlas_submit FULL PAYLOAD [{model_id}->{actual_model_id}] {ref_info}:\n"
                f"{_json.dumps(payload, ensure_ascii=False, indent=2)}")

    # Debug storage — so'nggi ref generatsiya uchun
    if has_refs:
        global _last_ref_debug
        _last_ref_debug = {
            "model_id":        model_id,
            "actual_model_id": actual_model_id,
            "payload":         payload.copy(),
            "image_urls":      list(image_urls) if image_urls else [],
        }

    async with aiohttp.ClientSession() as s:
        async with s.post(url, json=payload, headers=headers, timeout=aiohttp.ClientTimeout(total=30)) as r:
            resp = await r.json()
            logger.info(f"atlas_submit FULL RESPONSE:\n{_json.dumps(resp, ensure_ascii=False, indent=2)}")
            if has_refs:
                _last_ref_debug["response"] = resp
            return resp

async def _animate_generation(
    status_msg,
    model_name: str, cat: str, res: str, dur: int,
    pid: str,
    stop_event: asyncio.Event,
):
    """atlas_poll ishlayotganda animatsiyali loading ko'rsatadi.
    stop_event o'rnatilganda to'xtaydi.
    """
    SPINNERS  = ["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"]
    BAR_WIDTH = 14
    # Taxminiy yakunlanish vaqti (soniya)
    est = 150 if cat == "video" else 35

    loop  = asyncio.get_event_loop()
    start = loop.time()
    frame = 0
    pid_s = str(pid)[:8] + "…" if pid else ""

    while not stop_event.is_set():
        elapsed  = loop.time() - start
        progress = min(elapsed / est, 0.94)          # 94% dan oshmasin
        filled   = int(progress * BAR_WIDTH)
        bar      = "█" * filled + "░" * (BAR_WIDTH - filled)
        pct      = int(progress * 100)
        remaining = max(0, int(est - elapsed))
        sp        = SPINNERS[frame % len(SPINNERS)]

        info = f"🤖 <b>{model_name}</b>"
        if cat == "video" and res and dur:
            info += f"  |  🖥 {res}  |  ⏱ {dur}s"

        time_parts = [f"⏱ {int(elapsed)}s"]
        if remaining > 5:
            time_parts.append(T("gx45", v0=(remaining)))
        time_line = "  •  ".join(time_parts)

        text = (
            f"{sp} <b>Voro AI yaratmoqda...</b>\n\n"
            f"{info}\n\n"
            f"<code>[{bar}]</code> {pct}%\n\n"
            f"{time_line}  •  🆔 <code>{pid_s}</code>"
        )
        try:
            await status_msg.edit_text(text, parse_mode="HTML")
        except Exception:
            pass   # flood limit yoki xabar o'chirilgan

        frame += 1
        # stop_event ni kutamiz, 3.5s timeout bilan
        try:
            await asyncio.wait_for(asyncio.shield(stop_event.wait()), timeout=3.5)
        except asyncio.TimeoutError:
            pass


ATLAS_DONE_STATUSES   = {"completed", "succeeded", "done", "success", "finished"}
ATLAS_FAILED_STATUSES = {"failed", "error", "cancelled"}

# ════════════════════════════════════════════════════
#  SAMPLES — model/uslub namuna rasmlari
# ════════════════════════════════════════════════════
_SAMPLES_FILE = os.path.join(_BASE_DIR, "samples.json")
_samples_lock = threading.Lock()

def _samples_load() -> dict:
    """Barcha namunalarni yuklaydi: {key: {file_id, type, caption}}"""
    with _samples_lock:
        try:
            if os.path.exists(_SAMPLES_FILE):
                with open(_SAMPLES_FILE, "r", encoding="utf-8") as f:
                    return json.load(f)
        except Exception as e:
            logging.warning(f"_samples_load xato: {e}")
        return {}

def _sample_get(key: str) -> dict | None:
    """Bitta namunani qaytaradi yoki None."""
    return _samples_load().get(key)

def _sample_set(key: str, file_id: str, ftype: str, caption: str = ""):
    """Namunani saqlaydi yoki yangilaydi."""
    with _samples_lock:
        try:
            data = {}
            if os.path.exists(_SAMPLES_FILE):
                with open(_SAMPLES_FILE, "r", encoding="utf-8") as f:
                    data = json.load(f)
        except Exception:
            data = {}
        data[key] = {"file_id": file_id, "type": ftype, "caption": caption}
        tmp = _SAMPLES_FILE + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False)
        os.replace(tmp, _SAMPLES_FILE)
    logging.info(f"_sample_set: key={key!r} type={ftype}")

def _sample_del(key: str):
    """Namunani o'chiradi."""
    with _samples_lock:
        try:
            if not os.path.exists(_SAMPLES_FILE):
                return
            with open(_SAMPLES_FILE, "r", encoding="utf-8") as f:
                data = json.load(f)
            if key in data:
                del data[key]
                tmp = _SAMPLES_FILE + ".tmp"
                with open(tmp, "w", encoding="utf-8") as f:
                    json.dump(data, f, ensure_ascii=False)
                os.replace(tmp, _SAMPLES_FILE)
                logging.info(f"_sample_del: key={key!r} o'chirildi")
        except Exception as e:
            logging.warning(f"_sample_del xato: {e}")

# ════════════════════════════════════════════════════
#  PENDING JOBS — generatsiya tiklash tizimi
# ════════════════════════════════════════════════════
_PENDING_JOBS_FILE = os.path.join(_BASE_DIR, "pending_jobs.json")
_pending_jobs_lock = threading.Lock()

# ── Concurrent job limiti ──────────────────────────────────────────────────
MAX_CONCURRENT_JOBS = 2   # Bir foydalanuvchi bir vaqtda max shu qadar aktiv job
# _submitting: submit boshlangan lekin hali pending_jobs.json ga yozilmagan joblar.
# (atlas_submit → _add_pending_job oralig'idagi oyna) — key: uid, value: hisoblagich
_submitting: dict = {}
_submitting_lock   = threading.Lock()

def _load_pending_jobs() -> dict:
    """pending_jobs.json ni xavfsiz o'qiydi. Buzilgan bo'lsa .bak dan tiklanadi."""
    try:
        with open(_PENDING_JOBS_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    except FileNotFoundError:
        return {}
    except json.JSONDecodeError as e:
        logging.warning("pending_jobs.json buzilgan (%s) — .bak dan tiklanmoqda", e)
        bak = _PENDING_JOBS_FILE + ".bak"
        if os.path.exists(bak):
            try:
                with open(bak, "r", encoding="utf-8") as f:
                    data = json.load(f)
                logging.warning("pending_jobs.json.bak dan muvaffaqiyatli tiklandi")
                return data
            except (json.JSONDecodeError, OSError) as e2:
                logging.error("pending_jobs.json.bak ham buzilgan (%s) — bo'sh dict", e2)
        return {}

def _write_pending_jobs_nolock(jobs: dict):
    """Atomic yozish — lock OLMAYDI.
    Faqat _pending_jobs_lock allaqachon olingan kontekstdan chaqirilsin."""
    if os.path.exists(_PENDING_JOBS_FILE):
        shutil.copy2(_PENDING_JOBS_FILE, _PENDING_JOBS_FILE + ".bak")
    tmp = _PENDING_JOBS_FILE + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(jobs, f, ensure_ascii=False)
    os.replace(tmp, _PENDING_JOBS_FILE)

def _save_pending_jobs(jobs: dict):
    """Atomic write: lock oladi, yozadi.
    Tashqaridan (lockdan tashqari) chaqirishlar uchun."""
    with _pending_jobs_lock:
        _write_pending_jobs_nolock(jobs)

def _add_pending_job(pid: str, uid: int, chat_id: int, model_id: str,
                     prompt: str, cost: int, job_type: str, params: dict):
    """Yangi pending job yozadi (prediction_id → ma'lumotlar).
    O'qish + o'zgartirish + yozish bitta lock ostida atomic."""
    with _pending_jobs_lock:
        jobs = _load_pending_jobs()
        jobs[pid] = {
            "user_id":    uid,
            "chat_id":    chat_id,
            "model_id":   model_id,
            "prompt":     prompt,
            "cost":       cost,
            "type":       job_type,
            "params":     params,
            "created_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "status":     "pending",
            "deducted":   False,   # recovery: kredit yechilganligini kuzatadi
        }
        _write_pending_jobs_nolock(jobs)   # lock ichida — atomic
    logger.info(f"_add_pending_job: pid={pid[:8]} uid={uid} cost={cost}")

def _remove_pending_job(pid: str):
    """Pending job yozuvini o'chiradi.
    O'qish + o'chirish + yozish bitta lock ostida atomic."""
    with _pending_jobs_lock:
        jobs = _load_pending_jobs()
        if pid in jobs:
            del jobs[pid]
            _write_pending_jobs_nolock(jobs)   # lock ichida — atomic
    logger.info(f"_remove_pending_job: pid={pid[:8]} o'chirildi")

async def atlas_poll(prediction_id: str, max_wait=1800):
    """AtlasCloud polling — tarmoq xatolariga bardoshli (max 30 daqiqa)."""
    url = f"{ATLASCLOUD_BASE}/api/v1/model/prediction/{prediction_id}"
    headers = {"Authorization": f"Bearer {ATLASCLOUD_API_KEY}"}
    deadline = asyncio.get_event_loop().time() + max_wait
    import json as _json
    async with aiohttp.ClientSession() as s:
        while True:
            try:
                async with s.get(url, headers=headers, timeout=aiohttp.ClientTimeout(total=15)) as r:
                    data = await r.json()
                st = (data.get("data") or {}).get("status", "")
                logger.info(f"atlas_poll [{prediction_id[:8]}] status={st!r} keys={list((data.get('data') or {}).keys())}")
                if st in ATLAS_DONE_STATUSES or st in ATLAS_FAILED_STATUSES:
                    logger.info(f"atlas_poll FINAL:\n{_json.dumps(data, ensure_ascii=False)[:600]}")
                    return data
            except (aiohttp.ClientError, asyncio.TimeoutError, Exception) as e:
                logger.warning(f"atlas_poll [{prediction_id[:8]}] tarmoq xatosi: {e!r} — 5s kutilmoqda...")
            if asyncio.get_event_loop().time() > deadline:
                return {"data": {"status": "timeout"}}
            await asyncio.sleep(5)

