def _tr_label(txt):
    """TEMPLATES label/name larni joriy tilga o'giradi."""
    lang = _CUR_LANG.get('v', 'uz')
    if lang == 'uz':
        return txt
    e = _TR_LABEL.get(txt)
    if e and lang in e:
        return e[lang]
    return txt

def set_cur_lang(uid):
    try:
        lg = get_user_lang(uid)
        _CUR_LANG['v'] = lg if lg in ('uz','ru','en') else 'uz'
    except Exception:
        _CUR_LANG['v'] = 'uz'
    return _CUR_LANG['v']

def T(key, uid=None, **kwargs):
    if uid is not None:
        lang = None
        try: lang = get_user_lang(uid)
        except Exception: pass
        lang = lang if lang in ('uz','ru','en') else 'uz'
    else:
        lang = _CUR_LANG.get('v', 'uz')
    e = I18N.get(key)
    if not e:
        return key
    txt = e.get(lang) or e.get('uz') or key
    if kwargs:
        try: txt = txt.format(**kwargs)
        except Exception: pass
    return txt

def _llm_lang_note():
    """Foydalanuvchi tiliga qarab LLM javob tili ko'rsatmasi."""
    _l = _CUR_LANG.get('v', 'uz')
    if _l == 'ru':
        return ("\n\nIMPORTANT LANGUAGE RULE: The user has selected RUSSIAN as their language. "
                "Reply to the user ONLY in Russian. Generation prompts must still be written in English.")
    if _l == 'en':
        return ("\n\nIMPORTANT LANGUAGE RULE: The user has selected ENGLISH as their language. "
                "Reply to the user ONLY in English. Generation prompts must still be written in English.")
    return ""

async def cmd_start(update: Update, context: ContextTypes.DEFAULT_TYPE):
    _uid0 = update.effective_user.id
    if not get_user_lang(_uid0) and not (context.args and context.args[0].startswith('setlang')):
        await update.message.reply_text('Tilni tanlang / Выберите язык / Choose language:', reply_markup=lang_keyboard())
        return SELECT_CATEGORY
    return await _cmd_start_real(update, context)

async def _cmd_start_real(update: Update, context: ContextTypes.DEFAULT_TYPE):
    context.user_data.clear()
    uid  = update.effective_user.id
    set_cur_lang(uid)
    args = context.args or []

    # Ban tekshiruvi
    user = get_user(uid)
    if user.get("banned"):
        await update.effective_message.reply_text(T("m_banned_full"))
        return SELECT_CATEGORY

    # Kunlik bonus
    _db, _ds = await check_and_give_daily_bonus(uid)
    if _db:
        await update.effective_message.reply_text(
            T("fs79", v0=(_db), v1=(_ds)))
        user = get_user(uid)   # balansni yangilaymiz

    is_new = user.get("total", 0) == 0 and not user.get("referred_by")

    # ── Referral: faqat ALOQA saqlanadi, /start'da bonus berilmaydi ──
    # Bonus faqat do'stning birinchi xaridida beriladi (payment_ok da)
    if args and args[0].startswith("ref_") and not user.get("referred_by"):
        try:
            referrer_id = int(args[0][4:])
            if referrer_id != uid:
                # Aloqani yozamiz (bonus YO'Q) — _users_tx orqali atomik
                def _ref_mutate(users):
                    k = str(uid); rk = str(referrer_id)
                    users[k]["referred_by"] = referrer_id
                    # Referrer foydalanuvchi yo'q bo'lsa yaratamiz (RLock reentrant)
                    if rk not in users:
                        get_user(referrer_id)   # RLock reentrant — deadlock yo'q
                        users.update(load_users())   # txdan tashqarida o'zgargan — sync
                    if uid not in users.get(rk, {}).get("referrals", []):
                        users.setdefault(rk, {}).setdefault("referrals", []).append(uid)
                _users_tx(_ref_mutate)
                # Taklif qilganga xabar (bonus emas, shunchaki qo'shildi)
                try:
                    await context.bot.send_message(
                        referrer_id,
                        T("gx1", uid=referrer_id, v0=(REFERRAL_PERCENT)),
                        parse_mode="HTML")
                except: pass
        except (ValueError, KeyError): pass

    user = get_user(uid)
    bal  = get_balance(uid)
    if is_new:
        ref_note = T("gx2") if user.get("referred_by") else ""
        free_note = T("gx3", v0=(FREE_STARTER_TANGACHA))
        greeting = T("gx4", v0=(ref_note), v1=(bal), v2=(free_note))
    else:
        greeting = T("gx5", v0=(bal))
    _grp = update.effective_chat.type in ("group", "supergroup")
    await update.effective_message.reply_text(greeting + get_welcome(), parse_mode="HTML", reply_markup=persistent_kb(uid, for_group=_grp, first_name=update.effective_user.first_name or ""))
    return SELECT_CATEGORY

async def cmd_balance(update: Update, context: ContextTypes.DEFAULT_TYPE):
    u = get_user(update.effective_user.id)
    await update.message.reply_text(
        T("fs24", v0=(get_balance(update.effective_user.id)), v1=(u.get('total',0))),
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton(T("topup"), callback_data="buy")]]))

async def cmd_buy(update: Update, context: ContextTypes.DEFAULT_TYPE):
    bal = get_balance(update.effective_user.id)
    lines = "\n".join(f"{p['emoji']} <b>{p['tangacha']}⚡️</b> — {p['label']}: {p['desc']}" for p in STAR_PACKAGES)
    await update.message.reply_text(
        T("fs93", v0=(bal), v1=(lines)),
        parse_mode="HTML", reply_markup=buy_kb())

async def cmd_cancel(update: Update, context: ContextTypes.DEFAULT_TYPE):
    context.user_data.clear()
    _grp = update.effective_chat.type in ("group", "supergroup")
    await update.message.reply_text(T("m_cancelled_home"), reply_markup=persistent_kb(update.effective_user.id, for_group=_grp, first_name=update.effective_user.first_name or ""))
    return SELECT_CATEGORY

async def cmd_ref(update: Update, context: ContextTypes.DEFAULT_TYPE):
    uid  = update.effective_user.id
    u    = get_user(uid)
    refs = u.get("referrals", [])
    earned = u.get("ref_earned", 0)
    me   = await context.bot.get_me()
    link = f"https://t.me/{me.username}?start=ref_{uid}"

    # Nechtasi xarid qilganini hisoblash
    users_all = load_users()
    bought_count = sum(
        1 for rid in refs
        if users_all.get(str(rid), {}).get("referral_rewarded", False)
    )

    await update.message.reply_text(
        T("fs90", v0=(link), v1=(REFERRAL_PERCENT), v2=(len(refs)), v3=(bought_count), v4=(earned)),
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup([[
            InlineKeyboardButton(
                T("btn_send_friend"),
                url=f"https://t.me/share/url?url={link}&text=Voro+Creator+bilan+AI+video+va+rasm+yarating!")
        ]])
    )

async def cmd_promo(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    /promo KOD — promo-kodni qabul qiladi va balansga tangacha qo'shadi.

    promos.json formati:
        {"KOD": {"tangacha": 50, "limit": 100, "used_by": [], "expires": "2026-07-01"}}
    """
    uid  = update.effective_user.id
    args = context.args or []

    if not args:
        await update.message.reply_text(
            T("mp1"),
            parse_mode="HTML")
        return

    raw_code = args[0]
    code_upper = raw_code.upper()

    async with _promos_lock:
        promos = load_promos()

        # Katta-kichik harfga sezgir bo'lmagan qidirish
        matched_key = next(
            (k for k in promos if k.upper() == code_upper), None)

        if matched_key is None:
            await update.message.reply_text(
                T("mp2"),
                parse_mode="HTML")
            return

        promo = promos[matched_key]
        today = str(datetime.now().date())

        # Muddat tekshiruvi
        expires = promo.get("expires")
        if expires and today > expires:
            await update.message.reply_text(
                T("fs8", v0=(expires)),
                parse_mode="HTML")
            return

        # Limit tekshiruvi
        used_by = promo.get("used_by", [])
        limit   = promo.get("limit", 0)
        if limit and len(used_by) >= limit:
            await update.message.reply_text(
                T("mp3"),
                parse_mode="HTML")
            return

        # User oldin ishlatganmi?
        if uid in used_by:
            await update.message.reply_text(
                T("mp4"),
                parse_mode="HTML")
            return

        # Hamma tekshiruvlar o'tdi — balans qo'shish
        bonus = promo.get("tangacha", 0)
        promo["used_by"].append(uid)
        promos[matched_key] = promo
        save_promos(promos)

    # Lockdan tashqarida add_tangacha (o'z _users_lock i bor)
    await add_tangacha(uid, bonus)
    new_bal = get_balance(uid)
    await update.message.reply_text(
        T("fs81", v0=(bonus), v1=(new_bal)),
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup([
            [InlineKeyboardButton(T("start_creating"), callback_data="cat:video")],
        ]))

