async def elements_edit_name_handler(update: Update, context: ContextTypes.DEFAULT_TYPE) -> int:
    """ELEMENTS_EDIT_NAME — yangi nomni qabul qilib SQLite'da yangilaydi."""
    msg      = update.message
    new_name = (msg.text or "").strip()
    _eid     = context.user_data.get("elem_edit_id", "")
    _uid     = msg.from_user.id
    if not new_name:
        await msg.reply_text(T("m_name_empty1"))
        return ELEMENTS_EDIT_NAME
    if len(new_name) > 50:
        await msg.reply_text(T("m_name_long"))
        return ELEMENTS_EDIT_NAME
    _el = _elem_get(_uid, _eid)
    if not _el:
        await msg.reply_text(T("m_elem_noperm"))
        return SELECT_CATEGORY
    _old_name = _el["name"]
    _elem_update_name(_eid, new_name)
    context.user_data.pop("elem_edit_id", None)
    await msg.reply_text(
        T("fs52", v0=(_old_name), v1=(new_name)),
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup([
            [InlineKeyboardButton(T("library"), callback_data="elements_menu")],
            [InlineKeyboardButton(T("home"), callback_data="home")],
        ])
    )
    return SELECT_CATEGORY


async def elements_edit_photo_handler(update: Update, context: ContextTypes.DEFAULT_TYPE) -> int:
    """ELEMENTS_EDIT_PHOTOS — yangi rasmlarni yig'adi (almashtirish uchun)."""
    msg  = update.message
    _uid = msg.from_user.id
    b64s: list = context.user_data.setdefault("elem_edit_b64s", [])
    _eid = context.user_data.get("elem_edit_id", "")
    if len(b64s) >= 5:
        await msg.reply_text(T("m_max5"))
        return ELEMENTS_EDIT_PHOTOS
    if msg.photo:
        _fobj = await msg.photo[-1].get_file()
    elif msg.document and (msg.document.mime_type or "").startswith("image/"):
        _fobj = await msg.document.get_file()
    else:
        return ELEMENTS_EDIT_PHOTOS
    try:
        _raw = bytes(await _fobj.download_as_bytearray())
        import io as _eio3; from PIL import Image as _EP3
        _EP3.open(_eio3.BytesIO(_raw)).verify()
        b64s.append(base64.b64encode(_raw).decode())
    except Exception as _ie:
        await msg.reply_text(T("m_img_read"))
        return ELEMENTS_EDIT_PHOTOS
    _cnt = len(b64s)
    _kb  = InlineKeyboardMarkup([
        [InlineKeyboardButton(T("gx32", v0=(_cnt)), callback_data="elements_edit_photos_done")],
        [InlineKeyboardButton(T("back_cancel"),               callback_data=f"elements_view:{_eid}")],
    ])
    await msg.reply_text(
        T("fs46", v0=(_cnt)),
        parse_mode="HTML", reply_markup=_kb
    )
    return ELEMENTS_EDIT_PHOTOS


