    _kb  = InlineKeyboardMarkup([
        [InlineKeyboardButton(T("gx32", v0=(_cnt)), callback_data="elements_done")],
        [InlineKeyboardButton(T("back_cancel"),                 callback_data="elements_menu")],
    ])
    if _cnt < 5:
        await msg.reply_text(
            T("fs45", v0=(_cnt)),
            parse_mode="HTML", reply_markup=_kb
        )
    else:
        await msg.reply_text(
            T("m_5of5"),
            parse_mode="HTML", reply_markup=_kb
        )
    return ELEMENTS_CREATE_PHOTOS


