    _GEN_PREFIXES = (
        "tools_product_ad_style:", "tools_wedding_style:",
        "tools_thumb_style:", "fs_style:", "fs_terma_player:",
    )
    if context.user_data.get("is_generating") and (
        d in _GEN_CALLBACKS or d.startswith(_GEN_PREFIXES)
    ):
        await q.answer(T("m_gen_going"), show_alert=True)
        return context.user_data.get("state", SELECT_CATEGORY)

    # ── Til o'zgartirish (menyudan) ──
    if d == "change_lang":
        await q.edit_message_text("Tilni tanlang / Выберите язык / Choose language:", reply_markup=lang_keyboard())
        return SELECT_CATEGORY

    # ── Til tanlash ──
    if d.startswith('setlang_'):
        _lg = d[8:]
        set_user_lang(q.from_user.id, _lg)
        await q.answer()
        try: await q.edit_message_reply_markup(reply_markup=None)
        except Exception: pass
        return await _cmd_start_real(update, context)

    # ── no-op ──
    if d == "noop": return context.user_data.get("state", SELECT_CATEGORY)

    # ── ref:stay — Seedance multi-ref "➕ Yana yuboraman" tugmasi ──
    if d == "ref:stay":
        await q.answer()
        return UPLOAD_REF

    # ── HOME ──
    # ── NAMUNA KO'RISH (foydalanuvchi) ──────────────────────────────────────
    if d.startswith("sample_view:"):
        _sv_parts = d[len("sample_view:"):].split(":", 1)
        _sv_type  = _sv_parts[0]
        _sv_id    = _sv_parts[1] if len(_sv_parts) > 1 else ""
        _sv_key   = f"{_sv_type}/{_sv_id}"
        _sv_ex    = _sample_get(_sv_key)
        if not _sv_ex:
            await q.answer(T("m_sample_none"), show_alert=True)
            return SELECT_CATEGORY
        _sv_kb = InlineKeyboardMarkup([[InlineKeyboardButton(T("close"), callback_data="back:models")]])
        _sv_cap = f"📸 {_sv_ex.get('caption','') or 'Namuna natija'}"
        try:
            if _sv_ex["type"] == "photo":
                await q.message.reply_photo(_sv_ex["file_id"], caption=_sv_cap, reply_markup=_sv_kb)
            else:
                await q.message.reply_video(_sv_ex["file_id"], caption=_sv_cap, reply_markup=_sv_kb)
        except Exception as _sve:
            await q.answer(T("fs2", v0=(_sve)), show_alert=True)
        return SELECT_CATEGORY


    # ════════════════════════════════════════════════════
    #  MAIN MENU PHOTO ROUTING
    # ════════════════════════════════════════════════════
    if d.startswith("mainphoto:"):
        action = d.split(":", 1)[1]
        file_id = context.user_data.pop("mainphoto_file_id", None)
        context.user_data.pop("mainphoto_is_doc", None)

        if action == "cancel" or not file_id:
            await q.answer()
            try:
                await q.message.delete()
            except Exception:
                pass
            return SELECT_CATEGORY

        if action == "vagent":
            if not ANTHROPIC_API_KEY:
                await q.answer(T("m_vagent_off"), show_alert=True)
                return SELECT_CATEGORY
            # Rasmni yuklab base64 ga o'giramiz
            await q.answer(T("m_img_loading"))
            try:
                _fobj  = await context.bot.get_file(file_id)
                _raw   = bytes(await _fobj.download_as_bytearray())
                _b64   = base64.b64encode(_raw).decode()
            except Exception as _e:
                logger.warning(f"mainphoto:vagent rasm yuklanmadi: {_e}")
                await q.message.reply_text(T("m_img_fail1"))
                return SELECT_CATEGORY
            # Vagent holatini tozalaymiz
            context.user_data.pop("vagent_history",       None)
            context.user_data.pop("vagent_pending_tool",  None)
            context.user_data.pop("vagent_gen_count",     None)
            context.user_data.pop("vagent_session_notes", None)
            context.user_data["vagent_ref_b64"] = _b64
            _vg_kb = InlineKeyboardMarkup([
                [InlineKeyboardButton(T("back_main_menu"), callback_data="vagent:exit")]
            ])
            await q.message.reply_text(
                T("mp5") + f"⚡️ {T('vg_balance')}: <b>{bal}⚡️</b>  ·  {T('vg_perreq')}: {VAGENT_LLM_COST}⚡️",
                parse_mode="HTML",
                reply_markup=_vg_kb
            )
            return VAGENT_MODE

        if action == "i2v":
            # Rasmni AtlasCloud ga yuklaymiz (ref_url sifatida saqlaymiz)
            await q.answer(T("m_img_loading"))
            try:
                _fobj  = await context.bot.get_file(file_id)
                _raw   = bytes(await _fobj.download_as_bytearray())
                _url   = await atlas_upload_media(_raw, filename=f"mainphoto_{file_id}.jpg",
                                                   content_type="image/jpeg")
                if not _url:
                    raise ValueError("URL bo'sh")
            except Exception as _e:
                logger.warning(f"mainphoto:i2v upload xato: {_e}")
                await q.message.reply_text(T("m_img_fail2"))
                return SELECT_CATEGORY
            # Pre-load ref
            context.user_data["mainphoto_ref_url"] = _url
            # Faqat I2V video modellarni ko'rsatamiz
            _i2v_ids = ("image-to-video", "reference-to-video", "start-end-frame-to-video")
            _i2v_models = [m for m in VIDEO_MODELS if any(s in m["id"] for s in _i2v_ids)]
            context.user_data["cat"]  = "video"
            context.user_data["page"] = 0
            await q.edit_message_text(
                T("emt37", v0=(bal)),
                parse_mode="HTML",
                reply_markup=models_kb(_i2v_models, 0)
            )
            return SELECT_MODEL

    # ════════════════════════════════════════════════════
    #  VAGENT CALLBACKS
    # ════════════════════════════════════════════════════
    if d == "vagent_menu":
        if not ANTHROPIC_API_KEY:
            await q.answer(T("m_vagent_off"), show_alert=True)
            return SELECT_CATEGORY
        context.user_data.pop("vagent_history",       None)
        context.user_data.pop("vagent_ref_b64",       None)
        context.user_data.pop("vagent_pending_tool",  None)
        context.user_data.pop("vagent_gen_count",     None)
        context.user_data.pop("vagent_session_notes", None)
        _vg_kb = InlineKeyboardMarkup([
            [InlineKeyboardButton(T("back_main_menu"), callback_data="vagent:exit")]
        ])
        await q.answer()
        await q.message.reply_text(
            T("mp6") + f"⚡️ {T('vg_balance')}: <b>{bal}⚡️</b>  ·  {T('vg_perreq')}: {VAGENT_LLM_COST}⚡️",
            parse_mode="HTML",
            reply_markup=_vg_kb
        )
        return VAGENT_MODE

    if d in ("vagent:exit",):
        # Vagent holatini tozalab bosh menyuga qaytamiz
        context.user_data.pop("vagent_history",       None)
        context.user_data.pop("vagent_ref_b64",       None)
        context.user_data.pop("vagent_pending_tool",  None)
        context.user_data.pop("vagent_gen_count",     None)
        context.user_data.pop("vagent_session_notes", None)
        await q.answer()
        await _safe_edit(q, T("se2", v0=(bal)) + get_welcome(),
                         parse_mode="HTML", reply_markup=main_menu_kb())
        return SELECT_CATEGORY

    if d == "vagent:back":
        # Generatsiyadan Vagent suhbatiga qaytish (faqat tugma — xabar yubormaydi)
        await q.answer()
        _vg_back_kb = InlineKeyboardMarkup([
            [InlineKeyboardButton(T("back_main_menu"), callback_data="vagent:exit")]
        ])
        try:
            await q.message.edit_reply_markup(_vg_back_kb)
        except Exception:
            pass
        return VAGENT_MODE

    if d == "vagent:cancel":
        # Pending tool bekor qilinadi
        context.user_data.pop("vagent_pending_tool", None)
        history = context.user_data.get("vagent_history", [])
        # Tarixdagi oxirgi assistant xabarini ham olib tashlaymiz (tool_use bor edi)
        if history and history[-1].get("role") == "assistant":
            history.pop()
        await q.answer(T("m_cancelled"))
        _vg_kb = InlineKeyboardMarkup([
            [InlineKeyboardButton(T("back_main_menu"), callback_data="vagent:exit")]
        ])
        try:
            await q.message.edit_text(
                T("m_cancelled_new"),
                reply_markup=_vg_kb)
        except Exception:
            await q.message.reply_text(T("m_cancelled_new"),
                                        reply_markup=_vg_kb)
        return VAGENT_MODE

    if d == "vagent:approve":
        _pending = context.user_data.get("vagent_pending_tool")
        if not _pending:
            await q.answer(T("m_confirm_none"), show_alert=True)
            return VAGENT_MODE

        t_name = _pending["name"]
        t_args = _pending["args"]
        t_id   = _pending["id"]
        t_cost = _pending["cost"]

        # Balance tekshiruv
        _cur_bal = get_balance(uid)
        if _cur_bal < t_cost:
            await q.answer(
                T("fs1", v0=(t_cost), v1=(_cur_bal)),
                show_alert=True)
            return VAGENT_MODE

        await q.answer(T("m_confirmed"))

        # Status xabar
        _st_msg = await q.message.reply_text(
            T("m_gen_start"),
            parse_mode="HTML")

        _ref_b64 = context.user_data.get("vagent_ref_b64")
        _history = context.user_data.setdefault("vagent_history", [])

        # Approval xabarini o'chiramiz
        try:
            await q.message.delete()
        except Exception:
            pass

        _ok, _result_desc = await _vagent_run_tool(
            t_name, t_args, _ref_b64,
            uid, q.message, context, _st_msg)

        # Pending tozalaymiz
        context.user_data.pop("vagent_pending_tool", None)

        # Tool result tarixga qo'shamiz (Anthropic format)
        _tool_result_content = [
            {"type": "tool_result", "tool_use_id": t_id,
             "content": "success" if _ok else f"error: {_result_desc}"}
        ]
        _history.append({"role": "user", "content": _tool_result_content})

        if _ok:
            # Qisqa Claude follow-up (eng ko'pi 1 ta matn javob)
            _gc_now    = context.user_data.get("vagent_gen_count", 0)
            _sn_now    = context.user_data.get("vagent_session_notes", "")
            try:
                _follow = await _vagent_call_claude(
                    _history, has_ref=bool(_ref_b64),
                    gen_count=_gc_now, session_notes=_sn_now)
                _fc     = _follow.get("content", [])
                _fraw   = "\n".join(b["text"] for b in _fc
                                    if b.get("type") == "text" and b.get("text"))
                _fraw, _fn = _vagent_extract_note(_fraw)
                if _fn:
                    context.user_data["vagent_session_notes"] = _fn
                _ftext  = _vagent_strip_markdown(_fraw)
                if _ftext:
                    _history.append({"role": "assistant", "content": _ftext})
                    await q.message.reply_text(
                        _ftext,
                        reply_markup=InlineKeyboardMarkup([[
                            InlineKeyboardButton(T("back_main_menu"), callback_data="vagent:exit")
                        ]])
                    )
            except Exception as _fe:
                logger.warning(f"vagent:approve follow-up xato: {_fe}")

        return VAGENT_MODE

    # ════════════════════════════════════════════════════
    if d == "home":
        context.user_data.clear()
        await _safe_edit(q, T("se2", v0=(bal)) + get_welcome(),
                         parse_mode="HTML", reply_markup=main_menu_kb())
        return SELECT_CATEGORY

    # ── SHABLONLAR MENYUSI ──
    if d == "templates":
        rows = []
        for tmpl in TEMPLATES:
            rows.append([InlineKeyboardButton(
                f"{_tr_label(tmpl['name'])} — {_tr_label(tmpl['desc'])}",
                callback_data=f"tmpl:{tmpl['id']}"
            )])
        rows.append([InlineKeyboardButton(T("video_template"), callback_data="video_templates")])
        rows.append([InlineKeyboardButton(T("tools"), callback_data="tools_menu")])
        rows.append([InlineKeyboardButton(T("home"), callback_data="home")])
        await q.edit_message_text(
            T("emt35"),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup(rows)
        )
        return SELECT_CATEGORY

    # ── VIDEO SHABLONLAR SUBMENYUSI ──
    if d == "video_templates":
        await q.edit_message_text(
            T("emt38"),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton(T("football_invader"), callback_data="tmpl:football_invader")],
                [InlineKeyboardButton(T("back_templates"), callback_data="templates")],
            ])
        )
        return SELECT_CATEGORY

    # ── SHABLON BOSHLASH ──
    if d.startswith("tmpl:"):
        tmpl_id = d[5:]

        # ── FOOTBALL INVADER: maxsus video shablon ──
        if tmpl_id == "football_invader":
            _fi_mid  = "bytedance/seedance-2.0/reference-to-video"
            _fi_cost = calc_video_tangacha(_fi_mid, "720p", 8)
            _fi_bal  = get_balance(uid)
            if _fi_bal < _fi_cost:
                await q.edit_message_text(
                    T("emt22", v0=(_fi_cost), v1=(_fi_bal)),
                    parse_mode="HTML", reply_markup=lowbalance_kb()
                )
                return SELECT_CATEGORY
            context.user_data.clear()
            context.user_data["tmpl_id"]     = "football_invader"
            context.user_data["model_id"]    = _fi_mid
            context.user_data["model_name"]  = "Seedance 2.0"
            context.user_data["resolution"]  = "720p"
            context.user_data["aspect"]      = "9:16"
            context.user_data["cat"]         = "video"
            context.user_data["duration"]    = 8
            context.user_data["ref_base64s"] = []
            context.user_data["tmpl_cost_override"] = _fi_cost
            await q.edit_message_text(
                T("emt14", v0=(_fi_cost)),
                parse_mode="HTML",
                reply_markup=InlineKeyboardMarkup([[
                    InlineKeyboardButton(T("back"), callback_data="video_templates")
                ]])
            )
            return FOOTBALL_INVADER_PHOTO

        tmpl = _TEMPLATE_BY_ID.get(tmpl_id)
        if not tmpl:
            await q.answer(T("m_tmpl_none"), show_alert=True)
            return SELECT_CATEGORY
        if tmpl_id == "fotosessiya":
            _tmpl_mid = tmpl["model_id"]
            _tmpl_mname = next((m["name"] for m in IMAGE_MODELS if m["id"] == _tmpl_mid), _tmpl_mid.split("/")[1])
            context.user_data.clear()
            context.user_data["tmpl_id"]     = "fotosessiya"
            context.user_data["model_id"]    = _tmpl_mid
            context.user_data["model_name"]  = _tmpl_mname
            context.user_data["resolution"]  = tmpl["resolution"]
            context.user_data["aspect"]      = tmpl["aspect"]
            context.user_data["cat"]         = "image"
            context.user_data["ref_base64s"] = []
            # ── Yangi tartib: avval uslub tanlash, so'ngra rasm ──
            _fs_cost   = _fotosessiya_cost()
            _n_album   = len(_album_selectable_styles())
            _fs_rows   = []
            _fs_sdata  = _samples_load()
            for _fi in range(0, len(tmpl["styles"]), 2):
                _fp = tmpl["styles"][_fi:_fi+2]
                _fs_row = []
                for s in _fp:
                    _sk = f"style/{s['id']}"
                    _slabel = ("📸 " if _sk in _fs_sdata else "") + _tr_label(s["label"])
                    _fs_row.append(InlineKeyboardButton(_slabel, callback_data=f"fs_style:{s['id']}"))
                _fs_rows.append(_fs_row)
            _fs_rows.append([InlineKeyboardButton(
                T("gx46", v0=(_n_album), v1=(ALBUM_PRICE_DISCOUNT)),
                callback_data="fs_album"
            )])
            _fs_rows.append([InlineKeyboardButton(T("home"), callback_data="home")])
            await q.edit_message_text(
                T("emt56", v0=(_fs_cost)),
                parse_mode="HTML",
                reply_markup=InlineKeyboardMarkup(_fs_rows)
            )
            return FOTOSESSIYA_STYLE
        # Kelajakdagi shablon uchun yer
        await q.answer(T("m_soon"), show_alert=True)
        return SELECT_CATEGORY

    # ── MOTO / BMW / MERCEDES ──
    if d in ("fs_moto_sport_moto", "fs_moto_sport_bmw", "fs_moto_sport_mercedes"):
        tmpl      = _TEMPLATE_BY_ID.get("fotosessiya")
        style_obj = next((s for s in tmpl["styles"] if s["id"] == "moto_sport"), None)
        if not style_obj:
            await q.answer(T("m_style_none"), show_alert=True)
            return SELECT_CATEGORY
        cost = style_obj.get("cost") or _fotosessiya_cost()
        if bal < cost:
            await q.edit_message_text(
                T("emt22", v0=(cost), v1=(bal)),
                parse_mode="HTML", reply_markup=lowbalance_kb())
            return SELECT_CATEGORY
        # Sub-type tanlash
        _sub_key = d.replace("fs_moto_sport_", "")   # "moto", "bmw", "mercedes"
        _sub     = style_obj["subtypes"].get(_sub_key, {})
        _vehicle = _sub.get("vehicle", "")
        _label   = _sub.get("label", "Moto/Sport")
        _style_desc = style_obj["desc"].replace("{vehicle}", _vehicle)
        # Save state → rasm so'rash
        context.user_data["_fs_style_desc"]     = _style_desc
        context.user_data["original_idea"]      = f"Fotosessiya — {_label}"
        context.user_data["tmpl_cost_override"] = cost
        context.user_data.pop("enhanced_prompt", None)
        await q.edit_message_text(
            T("emt17", v0=(_label)),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton(T("back_style"), callback_data="fs_back_style")
            ]])
        )
        return FOTOSESSIYA_REF

    # ── TERMA A'ZOSI — RAQAM/FAMILIYA TANLANDI → so'ngra rasm so'raladi ──
    if d.startswith("fs_terma_player:"):
        _parts   = d.split(":", 2)
        _n       = _parts[1] if len(_parts) > 1 else "10"
        _surname = _parts[2] if len(_parts) > 2 else ""
        tmpl      = _TEMPLATE_BY_ID.get("fotosessiya")
        style_obj = next((s for s in tmpl["styles"] if s["id"] == "terma_azosi"), None)
        if not style_obj:
            await q.answer(T("m_style_none"), show_alert=True)
            return SELECT_CATEGORY
        cost = context.user_data.get("tmpl_cost_override") or style_obj.get("cost") or _fotosessiya_cost()
        if bal < cost:
            await q.edit_message_text(
                T("emt22", v0=(cost), v1=(bal)),
                parse_mode="HTML", reply_markup=lowbalance_kb())
            return SELECT_CATEGORY
        # Prompt'ga raqam va familiyani inject qilish
        _desc = style_obj["desc"]
        if _n == "0" or not _n:
            _desc = _desc.replace(", number {N} and name '{SURNAME}' on the back", "")
        else:
            _desc = _desc.replace("{N}", _n).replace("{SURNAME}", _surname)
        _player_label = f"#{_n} {_surname}".strip("# ") if (_n and _n != "0") else "O'zim"
        # Save state → ask for photo (Claude rasm bilan birga chaqiriladi)
        context.user_data["_fs_style_desc"]      = _desc
        context.user_data["original_idea"]       = f"Fotosessiya — Terma a'zosi {_player_label}"
        context.user_data["tmpl_cost_override"]  = cost
        context.user_data.pop("enhanced_prompt", None)
        await q.edit_message_text(
            T("emt28", v0=(_n), v1=(_surname)),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton(T("back_style"), callback_data="fs_back_style")
            ]])
        ) if (_n and _n != "0") else await q.edit_message_text(
            T("emt29"),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton(T("back_style"), callback_data="fs_back_style")
            ]])
        )
        return FOTOSESSIYA_REF

    # ── INSTAGRAM POST / STORIES ──
    if d in ("fs_instagram_post", "fs_instagram_stories"):
        import random as _rnd
        tmpl      = _TEMPLATE_BY_ID.get("fotosessiya")
        style_obj = next((s for s in tmpl["styles"] if s["id"] == "instagram"), None)
        if not style_obj:
            await q.answer(T("m_style_none"), show_alert=True)
            return SELECT_CATEGORY
        cost = _fotosessiya_cost()
        if bal < cost:
            await q.edit_message_text(
                T("emt22", v0=(cost), v1=(bal)),
                parse_mode="HTML", reply_markup=lowbalance_kb())
            return SELECT_CATEGORY
        is_stories = (d == "fs_instagram_stories")
        if is_stories:
            _style_desc = style_obj["desc_stories"]
            _label      = "Instagram Stories"
        else:
            _chosen     = _rnd.choice(style_obj["random_scenes"])
            _style_desc = style_obj["desc"].replace("{scene}", _chosen)
            _label      = "Instagram Post"
        # Save state → rasm so'rash
        context.user_data["_fs_style_desc"]     = _style_desc
        context.user_data["original_idea"]      = f"Fotosessiya — {_label}"
        context.user_data["tmpl_cost_override"] = cost
        context.user_data.pop("enhanced_prompt", None)
        await q.edit_message_text(
            T("emt17", v0=(_label)),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton(T("back_style"), callback_data="fs_back_style")
            ]])
        )
        return FOTOSESSIYA_REF

    # ── FIFA 2026 SELFI: FUTBOLCHI TANLASH ──
    if d.startswith("fs_fifa_player:") or d == "fs_fifa_no_player":
        import random as _rnd
        _user_refs = list(context.user_data.get("ref_base64s", []))  # [user_photo]
        _base_prompt = context.user_data.get("_fs_fifa_base_prompt", "")
        _cost = context.user_data.get("_fs_fifa_cost") or _fotosessiya_cost()

        if d.startswith("fs_fifa_player:"):
            _n = d.split(":", 1)[1]
            _raw_p = await _player_b64_from_sample(context.bot, _n)
            if not _raw_p:
                await q.answer(T("m_player_none"), show_alert=True)
                return FIFA_SELFI_PLAYER_PICK

            _p_b64 = base64.b64encode(_raw_p).decode()
            _player_label = _UZ_PLAYER_LABELS.get(_n, f"#{_n}")
            _user_photo   = _user_refs[0] if _user_refs else None
            if not _user_photo:
                await q.answer(T("m_selfie_none"), show_alert=True)
                return FIFA_SELFI_PLAYER_PICK

            # image 1 = user (asosiy — yuzlari saqlanadi), image 2 = futbolchi ref
            context.user_data["ref_base64s"] = [_user_photo, _p_b64]

            # ── GPT Image 2 (AtlasCloud) — FIFA selfi uchun maxsus model ──
            # nano-banana-2 ikki inson referensini chalkashtirib qo'shib yuboradi;
