            if meta.get("infinitetalk") and context.user_data.get("it_img_done"):
                context.user_data["it_audio_url"]   = None
                context.user_data["ref_audio_b64s"] = []
                context.user_data["ref_audio_urls"] = []
                context.user_data["duration"]       = 0
