async def fotosessiya_age(update: Update, context: ContextTypes.DEFAULT_TYPE) -> int:
    """Tug'ilgan kun uslubi: yosh raqamini qabul qilib generatsiyani boshlaydi."""
    msg = update.message
    uid = msg.from_user.id
    text = (msg.text or "").strip()

    # Validatsiya: 1–120 oralig'ida son bo'lsin
    if not text.isdigit() or not (1 <= int(text) <= 120):
        await msg.reply_text(
            T("m_only_num"),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton(T("back_style"), callback_data="fs_back_style")
            ]])
        )
        return FOTOSESSIYA_AGE

    age = int(text)
    tmpl     = _TEMPLATE_BY_ID["fotosessiya"]
    style_id = context.user_data.get("fs_style_id", "birthday")
    style_obj = next((s for s in tmpl["styles"] if s["id"] == style_id), None)
    if not style_obj:
        await msg.reply_text(T("m_style_none2"))
        return SELECT_CATEGORY

    # {age} ni haqiqiy raqam bilan almashtirish + 2 nazoratli variant
    import random as _rnd
    _scenes = [
        # VARIANT 1: Luxury car — oynada ko'pik bilan yozilgan raqam
        (
            f"SCENE: The person is standing confidently beside a gleaming high-end luxury sports car "
            f"(sleek premium supercar, no brand logos visible). "
            f"The car window has the number {age} written in white foam/spray — birthday celebration tradition, "
            f"the foam letters clearly spell '{age}' on the car window glass, large and legible. "
            f"Outdoor upscale setting, warm evening light on car and person."
        ),
        # VARIANT 2: Elegant venue — tort, lit number candles, sham yoqayotgan
        (
            f"SCENE: The person is standing at an elegant luxury party venue in front of a beautiful birthday cake. "
            f"The cake has lit number-shaped candles forming '{age}' — glowing, warm candlelight. "
            f"The person is holding a lighter and lighting the birthday candles on the cake, "
            f"hand with lighter close to the glowing candles, warm golden candlelight reflecting on the face. "
            f"Premium venue interior, sophisticated decor, celebratory atmosphere."
        ),
    ]
    _chosen_scene = _rnd.choice(_scenes)
    style_desc = (
        style_obj["desc"].replace("{age}", str(age))
        + f" {_chosen_scene}"
        + f" CRITICAL: The number {age} must be CLEARLY VISIBLE and CORRECTLY written as '{age}' "
        f"— large, sharp, perfectly readable, front and center. NOT blurry, NOT hidden, NOT wrong digits. "
        f"No car brand logos. Elegant luxurious outfit. DSLR photorealism, natural light, real skin, NOT CGI."
    )

    cost = context.user_data.get("tmpl_cost_override") or style_obj.get("cost") or _fotosessiya_cost()
    bal  = get_balance(uid)
    if bal < cost:
        await msg.reply_text(
            T("fs64", v0=(cost), v1=(bal)),
            parse_mode="HTML", reply_markup=lowbalance_kb())
        return SELECT_CATEGORY

    # ── Yangi tartib: style desc saqlash → rasm so'rash → fotosessiya_photo generatsiya ──
    context.user_data["_fs_style_desc"]     = style_desc
    context.user_data["original_idea"]      = f"Tug'ilgan kun — {age} yosh"
    context.user_data["tmpl_cost_override"] = cost
    context.user_data.pop("enhanced_prompt", None)

    await msg.reply_text(
        T("fs80", v0=(age)),
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup([[
            InlineKeyboardButton(T("back_style"), callback_data="fs_back_style")
        ]])
    )
    return FOTOSESSIYA_REF


