async def _tools_restore_run_gen_bg(msg, context: ContextTypes.DEFAULT_TYPE, status_msg):
    """Eski rasmni tiklash background — Nano Banana 2 bir bosqich."""
    uid  = msg.chat_id
    cost = context.user_data.get("tools_restore_cost", 9)
    b64  = context.user_data.get("restore_b64", "")

    RESTORE_MODEL  = "google/nano-banana-2/edit"
    RESTORE_ASP    = "3:4"
    RESTORE_RES    = "2K"
    RESTORE_PROMPT = (
        "Restore and colorize this old damaged photograph. Repair all damage: remove cracks, "
        "scratches, stains, fading, dust, and tears. Convert to natural realistic full color "
        "(add lifelike skin tones, natural hair color, realistic clothing colors). "
        "Make it look like a freshly taken modern high-quality photograph — sharp, clear, clean, well-lit. "
        "CRITICAL — preserve identity exactly: keep the person's face 100% faithful to the original — "
        "same exact facial features, eyes, nose, mouth, face shape, expression, age, and gender. "
        "Do NOT change the face, do NOT beautify or alter identity — only restore and colorize. "
        "The restored face must clearly be the SAME person. Keep the same pose, composition, and clothing "
        "(just restored and colorized). "
        "PHOTOREALISTIC: natural realistic skin texture with pores, realistic detail, natural lighting "
        "— like a real modern photograph, not artificial or plastic."
    )

    try:
        # Rasmni Atlas ga yuklaymiz
        img_bytes = base64.b64decode(b64)
        if img_bytes[:8] == b'\x89PNG\r\n\x1a\n':     ct, ext = "image/png",  "png"
        elif img_bytes[:6] in (b'GIF87a', b'GIF89a'):  ct, ext = "image/gif",  "gif"
        else:                                            ct, ext = "image/jpeg", "jpg"
        ref_url = await atlas_upload_media(bytes(img_bytes), filename=f"restore_ref.{ext}", content_type=ct)
        if not ref_url:
            raise Exception("REF_UPLOAD_FAILED")

        await status_msg.edit_text(
            T("mp31"),
            parse_mode="HTML"
        )

        submit = await atlas_submit(RESTORE_MODEL, RESTORE_PROMPT, RESTORE_ASP,
                                    resolution=RESTORE_RES, image_urls=[ref_url])
        logger.info(f"_tools_restore submit: {submit}")

        _s_msg = (submit.get("msg") or submit.get("message") or "").lower()
        if submit.get("code") == 402 or "insufficient" in _s_msg:
            raise Exception("SERVER_LOW_BALANCE")
        data = submit.get("data") or {}
        pid  = data.get("id")
        if not pid:
            raise Exception(f"INVALID_PARAMS:{json.dumps(submit, ensure_ascii=False)[:300]}")

        _add_pending_job(pid=pid, uid=uid, chat_id=msg.chat_id,
                         model_id=RESTORE_MODEL, prompt=RESTORE_PROMPT, cost=cost,
                         job_type="image", params={"res": RESTORE_RES, "dur": 0, "asp": RESTORE_ASP})

        _stop = asyncio.Event()
        _anim = asyncio.create_task(
            _animate_generation(status_msg, "🖼 Eski rasmni tiklash", "image", RESTORE_RES, 0, pid, _stop)
        )
        try:
            final = await atlas_poll(pid)
        finally:
            _stop.set(); _anim.cancel()
            try: await _anim
            except asyncio.CancelledError: pass

        fd = final.get("data") or {}
        st = fd.get("status", "")
        if st not in ATLAS_DONE_STATUSES:
            raise Exception(f"RESTORE_FAILED:{st}")

        def _pick_url(fd: dict):
            out_arr = fd.get("outputs") or fd.get("images") or fd.get("urls") or []
            if out_arr:
                return out_arr[0] if isinstance(out_arr, list) else str(out_arr)
            out_s = fd.get("output")
            if isinstance(out_s, list) and out_s:  return out_s[0]
            if isinstance(out_s, str):             return out_s
            for _f in ("url", "image_url", "result", "media_url"):
                _v = fd.get(_f)
                if _v and isinstance(_v, str): return _v
            return None

        media_url = _pick_url(fd)

        _ded_ok = await deduct_tangacha(uid, cost)
        if not _ded_ok:
            logger.error(f"deduct_tangacha FAILED uid={uid} cost={cost} — kredit yetmadi")
        nb = get_balance(uid)

        caption = T("gx43", v0=(nb))
        _ANIM_COST = 26   # Kling v3.0 std i2v · 6s · $0.071/s × 2.5 margin / $0.042 ≈ 26
        _done_kb = InlineKeyboardMarkup([
            [InlineKeyboardButton(T("gx44", v0=(_ANIM_COST)), callback_data="tools_restore_animate")],
            [InlineKeyboardButton(T("restore_new"), callback_data="tools_restore")],
            [InlineKeyboardButton(T("home"),          callback_data="home")],
        ])

        await status_msg.delete()
        _sent_file_id = None
        if media_url:
            try:
                _sm = await msg.reply_photo(photo=media_url, caption=caption,
                                            parse_mode="HTML", reply_markup=_done_kb)
                _sent_file_id = _sm.photo[-1].file_id if _sm.photo else None
            except Exception:
                try:
                    import io as _io
                    async with aiohttp.ClientSession() as _dl_s:
                        async with _dl_s.get(media_url, timeout=aiohttp.ClientTimeout(total=120)) as _dl_r:
                            _fb = await _dl_r.read()
                    from telegram import InputFile as _IF
                    _sm = await msg.reply_photo(
                        photo=_IF(_io.BytesIO(_fb), filename="restored.jpg"),
                        caption=caption, parse_mode="HTML", reply_markup=_done_kb)
                    _sent_file_id = _sm.photo[-1].file_id if _sm.photo else None
                except Exception:
                    await msg.reply_text(
                        T("fs54", v0=(media_url[:200])),
                        parse_mode="HTML", reply_markup=_done_kb)
        else:
            await msg.reply_text(T("m_done_nourl"), reply_markup=_done_kb)

        # Jonlantirish uchun natijani saqlaymiz
        context.user_data["restore_result_file_id"] = _sent_file_id
        context.user_data["restore_result_url"]     = media_url or ""

        await save_history(uid, {
            "ts":      datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "model":   RESTORE_MODEL,
            "prompt":  RESTORE_PROMPT,
            "cost":    cost,
            "type":    "image",
            "file_id": _sent_file_id,
        })
        _remove_pending_job(pid)

    except Exception as e:
        logger.exception("_tools_restore_run_gen_bg xato")
        err_str = str(e)
        try:
            if "REF_UPLOAD_FAILED" in err_str:
                await status_msg.edit_text(
                    T("mp32"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            elif "SERVER_LOW_BALANCE" in err_str:
                await status_msg.edit_text(
                    T("m_aqlbek_busy1"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            elif "INVALID_PARAMS:" in err_str:
                await status_msg.edit_text(
                    T("m_param_err"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            else:
                await status_msg.edit_text(
                    T("m_restore_err"),
                    parse_mode="HTML", reply_markup=back_home_kb())
        except Exception:
            pass
    finally:
        context.user_data["is_generating"] = False


async def _tools_animate_run_gen_bg(msg, context: ContextTypes.DEFAULT_TYPE, status_msg):
    """Tiklanган rasmni Kling v3.0 std i2v orqali jonlantiradi (6 soniya)."""
    uid  = msg.chat_id
    cost = context.user_data.get("tools_animate_cost") or calc_video_tangacha("bytedance/seedance-2.0/image-to-video", "720p", 5)

    ANIM_MODEL  = "bytedance/seedance-2.0/image-to-video"
    ANIM_DUR    = 5
    ANIM_RES    = "720p"
    ANIM_ASP    = "adaptive"
    ANIM_PROMPT = (
        "A gentle, lifelike portrait animation of the person. Very subtle and natural movements only: "
        "the person slowly blinks their eyes naturally, then looks down softly, then looks directly at "
        "the camera and gives a warm, sincere, genuine smile. A subtle friendly eyebrow raise. At the end, "
        "a small warm farewell gesture (a gentle nod or soft goodbye expression). Keep movements minimal, "
        "smooth, slow, and natural — NO sudden or exaggerated motion, NO distortion. The face must stay "
        "perfectly consistent and identical to the photo throughout — preserve the person's identity "
        "completely. Calm, warm, emotional, realistic. Soft natural lighting, subtle realistic motion, "
        "cinematic and heartfelt."
    )

    try:
        # 1. Tiklanган rasmni yuklab olish (Telegram file_id yoki URL orqali)
        _file_id = context.user_data.get("restore_result_file_id")
        _url     = context.user_data.get("restore_result_url", "")

        img_bytes = None
        if _file_id:
            try:
                _tg_file = await context.bot.get_file(_file_id)
                img_bytes = bytes(await _tg_file.download_as_bytearray())
            except Exception as _fe:
                logger.warning(f"_tools_animate: Telegram file_id yuklab bo'lmadi: {_fe}")

        if not img_bytes and _url:
            try:
                async with aiohttp.ClientSession() as _s:
                    async with _s.get(_url, timeout=aiohttp.ClientTimeout(total=60)) as _r:
                        img_bytes = bytes(await _r.read())
            except Exception as _ue:
                logger.warning(f"_tools_animate: URL yuklab bo'lmadi: {_ue}")

        if not img_bytes:
            raise Exception("ANIM_IMG_FAILED")

        await status_msg.edit_text(
            T("mp33"),
            parse_mode="HTML"
        )

        # 2. Atlas ga ref yuklash
        anim_ref_url = await atlas_upload_media(img_bytes, filename="animate_ref.jpg")
        if not anim_ref_url:
            raise Exception("REF_UPLOAD_FAILED")

        await status_msg.edit_text(
            T("mp34"),
            parse_mode="HTML"
        )

        # 3. Kling v3.0 std image-to-video submit
        submit = await atlas_submit(
            ANIM_MODEL, ANIM_PROMPT, ANIM_ASP,
            resolution=ANIM_RES,
            duration=ANIM_DUR,
            image_url=anim_ref_url
        )
        logger.info(f"_tools_animate submit: {submit}")

        _s_msg = (submit.get("msg") or submit.get("message") or "").lower()
        if submit.get("code") == 402 or "insufficient" in _s_msg:
            raise Exception("SERVER_LOW_BALANCE")
        data = submit.get("data") or {}
        pid  = data.get("id")
        if not pid:
            raise Exception(f"INVALID_PARAMS:{json.dumps(submit, ensure_ascii=False)[:300]}")

        _add_pending_job(pid=pid, uid=uid, chat_id=msg.chat_id,
                         model_id=ANIM_MODEL, prompt=ANIM_PROMPT, cost=cost,
                         job_type="video", params={"res": ANIM_RES, "dur": ANIM_DUR, "asp": ANIM_ASP})

        _stop = asyncio.Event()
        _anim_task = asyncio.create_task(
            _animate_generation(status_msg, "🎬 Jonlantirish", "video", ANIM_RES, ANIM_DUR, pid, _stop)
        )
        try:
            final = await atlas_poll(pid)
        finally:
            _stop.set(); _anim_task.cancel()
            try: await _anim_task
            except asyncio.CancelledError: pass

        fd = final.get("data") or {}
        st = fd.get("status", "")
        if st not in ATLAS_DONE_STATUSES:
            raise Exception(f"ANIM_FAILED:{st}")

        # Video URL olish
        out_arr = fd.get("outputs") or fd.get("videos") or fd.get("urls") or []
        if out_arr:
            video_url = out_arr[0] if isinstance(out_arr, list) else str(out_arr)
        else:
            out_s = fd.get("output")
            if isinstance(out_s, list) and out_s:   video_url = out_s[0]
            elif isinstance(out_s, str):             video_url = out_s
            else:
                video_url = next(
                    (fd.get(f) for f in ("url", "video_url", "result", "media_url") if fd.get(f)),
                    None)

        _ded_ok = await deduct_tangacha(uid, cost)
        if not _ded_ok:
            logger.error(f"deduct_tangacha FAILED uid={uid} cost={cost} — kredit yetmadi")
        nb = get_balance(uid)

        caption = (
            T("rt20", v0=(nb))
        )
        _done_kb2 = InlineKeyboardMarkup([
            [InlineKeyboardButton(T("restore_new"), callback_data="tools_restore")],
            [InlineKeyboardButton(T("home"),          callback_data="home")],
        ])

        try: await status_msg.delete()
        except: pass

        if video_url:
            try:
                await msg.reply_video(video=video_url, caption=caption,
                                      parse_mode="HTML", reply_markup=_done_kb2)
            except Exception:
                try:
                    async with aiohttp.ClientSession() as _dl_s:
                        async with _dl_s.get(video_url, timeout=aiohttp.ClientTimeout(total=180)) as _dl_r:
                            _vb = await _dl_r.read()
                    import io as _io
                    from telegram import InputFile as _IF
                    await msg.reply_video(
                        video=_IF(_io.BytesIO(_vb), filename="animated.mp4"),
                        caption=caption, parse_mode="HTML", reply_markup=_done_kb2)
                except Exception:
                    await msg.reply_text(
                        T("fs87", v0=(video_url[:200])),
                        parse_mode="HTML", reply_markup=_done_kb2)
        else:
            await msg.reply_text(T("m_anim_nourl"), reply_markup=_done_kb2)

        _remove_pending_job(pid)

    except Exception as e:
        logger.exception("_tools_animate_run_gen_bg xato")
        err_str = str(e)
        try:
            if "ANIM_IMG_FAILED" in err_str:
                await status_msg.edit_text(
                    T("m_img_none_r"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            elif "REF_UPLOAD_FAILED" in err_str:
                await status_msg.edit_text(
                    T("m_imgfail_v2"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            elif "SERVER_LOW_BALANCE" in err_str:
                await status_msg.edit_text(
                    T("m_aqlbek_busy1"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            elif "INVALID_PARAMS:" in err_str:
                await status_msg.edit_text(
                    T("m_param_err"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            else:
                await status_msg.edit_text(
                    T("m_anim_err"),
                    parse_mode="HTML", reply_markup=back_home_kb())
        except Exception:
            pass
    finally:
        context.user_data["is_generating"] = False


