async def tools_product_ad_photo(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """TOOLS_PRODUCT_AD_REF holati — mahsulot rasmi qabul qilib, sahna uslubini so'raydi."""
    msg = update.message
    uid = msg.chat_id

    if not (msg.photo or (msg.document and msg.document.mime_type and msg.document.mime_type.startswith("image/"))):
        await msg.reply_text(
            T("m_send_product"),
            parse_mode="HTML"
        )
        return TOOLS_PRODUCT_AD_REF

    cost = context.user_data.get("product_ad_cost", 9)
    bal  = get_balance(uid)
    if bal < cost:
        await msg.reply_text(
            T("fs64", v0=(cost), v1=(bal)),
            parse_mode="HTML", reply_markup=lowbalance_kb())
        return SELECT_CATEGORY

    try:
        if msg.photo:
            file_obj = await msg.photo[-1].get_file()
        else:
            file_obj = await msg.document.get_file()
        img_bytes = await file_obj.download_as_bytearray()
        b64 = base64.b64encode(bytes(img_bytes)).decode()
    except Exception as e:
        logger.warning(f"tools_product_ad_photo yuklab olish xato: {e}")
        await msg.reply_text(T("m_img_dl2"))
        return TOOLS_PRODUCT_AD_REF

    context.user_data["product_ad_b64"]  = b64
    context.user_data["product_ad_cost"] = cost

    await msg.reply_text(
        T("mp35"),
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup([
            [
                InlineKeyboardButton(T("style_luxury"),     callback_data="tools_product_ad_style:luxury"),
                InlineKeyboardButton(T("style_natural"), callback_data="tools_product_ad_style:natural"),
            ],
            [
                InlineKeyboardButton(T("style_minimalist"),    callback_data="tools_product_ad_style:minimalist"),
                InlineKeyboardButton(T("style_colorful"), callback_data="tools_product_ad_style:colorful"),
            ],
            [InlineKeyboardButton(T("back_green"), callback_data="tools_product_ad")],
        ])
    )
    return SELECT_CATEGORY


async def _tools_product_ad_run_gen_bg(msg, context: ContextTypes.DEFAULT_TYPE, status_msg):
    """Mahsulot reklamasi background — Nano Banana 2 orqali reklama sahnasi yaratadi."""
    uid      = msg.chat_id
    cost     = context.user_data.get("product_ad_cost", 9)
    b64      = context.user_data.get("product_ad_b64", "")
    style_key= context.user_data.get("product_ad_style", "luxury")

    AD_MODEL = "google/nano-banana-2/edit"
    AD_RES   = "2K"
    AD_ASP   = "1:1"

    _STYLE_SUFFIXES = {
        "luxury":     "luxurious elegant setting — marble surface, soft silk or premium materials, "
                      "gold accents, sophisticated dramatic lighting, high-end luxury brand aesthetic.",
        "natural":    "natural organic setting — wood, stone, fresh flowers, leaves, soft natural daylight, "
                      "clean eco-friendly aesthetic.",
        "minimalist": "clean minimalist setting — simple elegant backdrop, lots of negative space, "
                      "soft even lighting, modern sophisticated simplicity.",
        "colorful":   "vibrant colorful setting — bold complementary colors, dynamic creative composition, "
                      "bright punchy lighting, eye-catching modern advertising style.",
    }
    _style_suffix = _STYLE_SUFFIXES.get(style_key, _STYLE_SUFFIXES["luxury"])

    AD_PROMPT = (
        "Place this product into a beautiful professional commercial advertisement scene. "
        "IMPORTANT — keep the product itself as faithful as possible: preserve its shape, color, "
        "design, logo, and label as accurately as you can. Create an attractive premium scene AROUND "
        "the product. Add professional studio lighting, realistic soft shadows and reflections, and a "
        "polished high-end commercial aesthetic. Photorealistic, magazine-quality product advertising photography. "
        + _style_suffix
    )

    try:
        img_bytes = base64.b64decode(b64)
        if img_bytes[:8] == b'\x89PNG\r\n\x1a\n':     ct, ext = "image/png",  "png"
        elif img_bytes[:6] in (b'GIF87a', b'GIF89a'):  ct, ext = "image/gif",  "gif"
        else:                                            ct, ext = "image/jpeg", "jpg"

        ref_url = await atlas_upload_media(bytes(img_bytes), filename=f"product_ad_ref.{ext}", content_type=ct)
        if not ref_url:
            raise Exception("REF_UPLOAD_FAILED")

        await status_msg.edit_text(
            T("mp36"),
            parse_mode="HTML"
        )

        submit = await atlas_submit(AD_MODEL, AD_PROMPT, AD_ASP,
                                    resolution=AD_RES, image_urls=[ref_url])
        logger.info(f"_tools_product_ad submit: {submit}")

        _s_msg = (submit.get("msg") or submit.get("message") or "").lower()
        if submit.get("code") == 402 or "insufficient" in _s_msg:
            raise Exception("SERVER_LOW_BALANCE")
        data = submit.get("data") or {}
        pid  = data.get("id")
        if not pid:
            raise Exception(f"INVALID_PARAMS:{json.dumps(submit, ensure_ascii=False)[:300]}")

        _add_pending_job(pid=pid, uid=uid, chat_id=msg.chat_id,
                         model_id=AD_MODEL, prompt=AD_PROMPT, cost=cost,
                         job_type="image", params={"res": AD_RES, "dur": 0, "asp": AD_ASP})

        _stop = asyncio.Event()
        _anim = asyncio.create_task(
            _animate_generation(status_msg, "📦 Mahsulot reklamasi", "image", AD_RES, 0, pid, _stop)
        )
        try:
            final = await atlas_poll(pid)
        finally:
            _stop.set(); _anim.cancel()
            try: await _anim
            except asyncio.CancelledError: pass

        fd = final.get("data") or {}
        st = fd.get("status", "")
        if st not in ATLAS_DONE_STATUSES:
            raise Exception(f"AD_FAILED:{st}")

        def _pick_url(fd: dict):
            out_arr = fd.get("outputs") or fd.get("images") or fd.get("urls") or []
            if out_arr:
                return out_arr[0] if isinstance(out_arr, list) else str(out_arr)
            out_s = fd.get("output")
            if isinstance(out_s, list) and out_s:  return out_s[0]
            if isinstance(out_s, str):              return out_s
            for _f in ("url", "image_url", "result", "media_url"):
                _v = fd.get(_f)
                if _v and isinstance(_v, str): return _v
            return None

        media_url = _pick_url(fd)

        _ded_ok = await deduct_tangacha(uid, cost)
        if not _ded_ok:
            logger.error(f"deduct_tangacha FAILED uid={uid} cost={cost} — kredit yetmadi")
        nb = get_balance(uid)

        _STYLE_LABELS = {
            "luxury":     "💎 Hashamatli",
            "natural":    "🌿 Tabiiy/Organik",
            "minimalist": "⬜ Minimalist",
            "colorful":   "🎨 Rangli/Yorqin",
        }
        _style_label = _STYLE_LABELS.get(style_key, style_key)

        caption = (
            T("rt21", v0=(_style_label), v1=(nb))
        )
        _done_kb = InlineKeyboardMarkup([
            [InlineKeyboardButton(T("other_style"),       callback_data="tools_product_ad")],
            [InlineKeyboardButton(T("tools"),              callback_data="tools_menu")],
            [InlineKeyboardButton(T("home"),        callback_data="home")],
        ])

        try: await status_msg.delete()
        except: pass

        _sent_file_id = None
        if media_url:
            try:
                _sm = await msg.reply_photo(photo=media_url, caption=caption,
                                            parse_mode="HTML", reply_markup=_done_kb)
                _sent_file_id = _sm.photo[-1].file_id if _sm.photo else None
            except Exception:
                try:
                    import io as _io
                    async with aiohttp.ClientSession() as _dl_s:
                        async with _dl_s.get(media_url, timeout=aiohttp.ClientTimeout(total=120)) as _dl_r:
                            _fb = await _dl_r.read()
                    from telegram import InputFile as _IF
                    _sm = await msg.reply_photo(
                        photo=_IF(_io.BytesIO(_fb), filename="ad_result.jpg"),
                        caption=caption, parse_mode="HTML", reply_markup=_done_kb)
                    _sent_file_id = _sm.photo[-1].file_id if _sm.photo else None
                except Exception:
                    await msg.reply_text(
                        T("fs55", v0=(media_url[:200])),
                        parse_mode="HTML", reply_markup=_done_kb)
        else:
            await msg.reply_text(T("m_done_nourl"), reply_markup=_done_kb)

        await save_history(uid, {
            "ts":      datetime.utcnow().isoformat(timespec="seconds") + "Z",
            "model":   AD_MODEL,
            "prompt":  AD_PROMPT,
            "cost":    cost,
            "type":    "image",
            "file_id": _sent_file_id,
        })
        _remove_pending_job(pid)

    except Exception as e:
        logger.exception("_tools_product_ad_run_gen_bg xato")
        err_str = str(e)
        try:
            if "REF_UPLOAD_FAILED" in err_str:
                await status_msg.edit_text(
                    T("mp32"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            elif "SERVER_LOW_BALANCE" in err_str:
                await status_msg.edit_text(
                    T("m_aqlbek_busy1"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            elif "INVALID_PARAMS:" in err_str:
                await status_msg.edit_text(
                    T("m_param_err"),
                    parse_mode="HTML", reply_markup=back_home_kb())
            else:
                await status_msg.edit_text(
                    T("m_ad_err"),
                    parse_mode="HTML", reply_markup=back_home_kb())
        except Exception:
            pass
    finally:
        context.user_data["is_generating"] = False


