async def admin_media_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin tomonidan rasm/video yuklash handleri (namunalar) — group=-2."""
    uid = update.effective_user.id
    if uid not in ADMIN_IDS: return
    if context.user_data.get("admin_state") != "upload_sample": return
    _key = context.user_data.get("admin_sample_key", "")
    if not _key:
        await update.message.reply_text(T("m_key_none"))
        context.user_data["admin_state"] = None
        raise ApplicationHandlerStop
    msg = update.message
    _file_id = _ftype = None
    if msg.photo:
        _file_id, _ftype = msg.photo[-1].file_id, "photo"
    elif msg.video:
        _file_id, _ftype = msg.video.file_id, "video"
    elif msg.document:
        _mt = msg.document.mime_type or ""
        if _mt.startswith("image/"):   _file_id, _ftype = msg.document.file_id, "photo"
        elif _mt.startswith("video/"): _file_id, _ftype = msg.document.file_id, "video"
    if not _file_id:
        await update.message.reply_text(T("m_only_iv"))
        raise ApplicationHandlerStop
    _caption = (msg.caption or "").strip()
    _sample_set(_key, _file_id, _ftype, _caption)
    context.user_data["admin_state"] = None
    context.user_data.pop("admin_sample_key", None)
    _icon = "📸" if _ftype == "photo" else "🎬"
    await update.message.reply_text(
        T("fs32", v0=(_icon), v1=(_ftype), v2=(_key), v3=('📝 ' + _caption if _caption else '')),
        parse_mode="HTML",
        reply_markup=InlineKeyboardMarkup([[
            InlineKeyboardButton(T("back_samples"), callback_data="adm:samples"),
            InlineKeyboardButton(T("admin_panel"), callback_data="adm:menu"),
        ]])
    )
    raise ApplicationHandlerStop

async def group_admin_guard(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Guruhda faqat ADMIN_IDS (siz) bilan bot ishlaydi.
    Boshqa har kim yozsa/tugma bossa → bot butunlay jim turadi (javob bermasdan).
    Shaxsiy chat → o'zgarmaydi (hamma uchun normal).
    """
    chat = update.effective_chat
    user = update.effective_user
    if chat and chat.type in ("group", "supergroup"):
        if not user or user.id not in ADMIN_IDS:
            # Guruhda admin emas → barcha handlerlarni to'xtatamiz (jim)
            raise ApplicationHandlerStop


