def _admin_stats_text() -> str:
    users = load_users()
    today = str(datetime.now().date())
    total        = len(users)
    active_today = sum(1 for u in users.values() if u.get("last_active") == today)
    new_today    = sum(1 for u in users.values() if u.get("joined")      == today)
    total_gen    = sum(u.get("total", 0)      for u in users.values())
    total_stars  = sum(u.get("stars_paid", 0) for u in users.values())
    total_bal    = sum(u.get("tangacha", 0)   for u in users.values())
    banned_cnt   = sum(1 for u in users.values() if u.get("banned"))
    total_refs   = sum(len(u.get("referrals", [])) for u in users.values())
    top5 = sorted(users.items(), key=lambda x: x[1].get("total", 0), reverse=True)[:5]
    top_lines = "\n".join(
        f"  {i+1}. <code>{uid}</code> — {u.get('total',0)} gen · {u.get('tangacha',0)}⚡️ · {u.get('stars_paid',0)}⭐️"
        for i, (uid, u) in enumerate(top5))
    return (
        T("rt27", v0=(total), v1=(active_today), v2=(new_today), v3=(total_gen), v4=(total_stars), v5=(total_bal), v6=(banned_cnt), v7=(total_refs), v8=(top_lines))
    )

