async def admin_input_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin panel matn input handleri — group=-2, ConversationHandler dan oldin ishlaydi."""
    uid = update.effective_user.id
    if uid not in ADMIN_IDS: return
    admin_state = context.user_data.get("admin_state")
    if not admin_state: return

    text = update.message.text.strip()
    back_kb = InlineKeyboardMarkup([[InlineKeyboardButton(T("back_admin"), callback_data="adm:menu")]])

    if admin_state == "add_balance":
        target_from_state = context.user_data.get("admin_target")
        try:
            if target_from_state:
                target_uid, amount = target_from_state, int(text)
                context.user_data.pop("admin_target", None)
            else:
                parts = text.split(); target_uid, amount = int(parts[0]), int(parts[1])
            await add_tangacha(target_uid, amount)
            nb = get_balance(target_uid)
            await update.message.reply_text(
                T("fs30", v0=(target_uid), v1=(amount), v2=(nb)),
                parse_mode="HTML", reply_markup=back_kb)
            context.user_data["admin_state"] = None
            try:
                await context.bot.send_message(target_uid,
                    T("gx42", uid=target_uid, v0=(amount), v1=(nb)), parse_mode="HTML")
            except: pass
        except:
            await update.message.reply_text(T("m_fmt_uid"), parse_mode="HTML")
        raise ApplicationHandlerStop

    if admin_state == "sub_balance":
        try:
            parts = text.split(); target_uid, amount = int(parts[0]), int(parts[1])
            _sub_result = [None]
            if _db_user_exists(target_uid):
                c = _webdb()
                try:
                    c.execute("UPDATE users SET balance=MAX(balance-?,0) WHERE tg_id=?",
                              (amount, target_uid))
                    c.commit()
                    r = c.execute("SELECT balance FROM users WHERE tg_id=?",
                                  (target_uid,)).fetchone()
                    _sub_result[0] = int(r[0] or 0) if r else 0
                finally:
                    c.close()
            else:
                def _sub_mutate(users):
                    k = str(target_uid)
                    if k not in users: raise KeyError
                    users[k]["tangacha"] = max(0, users[k].get("tangacha", 0) - amount)
                    _sub_result[0] = users[k]["tangacha"]
                _users_tx(_sub_mutate)
            await update.message.reply_text(
                T("fs29", v0=(target_uid), v1=(amount), v2=(_sub_result[0])),
                parse_mode="HTML", reply_markup=back_kb)
            context.user_data["admin_state"] = None
        except:
            await update.message.reply_text(T("m_fmt_uid2"), parse_mode="HTML")
        raise ApplicationHandlerStop

    if admin_state == "search_user":
        try:
            target_uid = int(text)
            users = load_users(); k = str(target_uid)
            if k not in users:
                await update.message.reply_text(T("fs70", v0=(target_uid)), parse_mode="HTML")
            else:
                u = users[k]
                banned_s = "🚫 Ha" if u.get("banned") else "✅ Yo'q"
                await update.message.reply_text(
                    f"👤 <b>Foydalanuvchi</b>\n\n"
                    f"🆔 ID: <code>{target_uid}</code>\n"
                    f"⚡️ Balans: <b>{get_balance(target_uid)}⚡️</b>\n"
                    f"🎬 Jami gen: <b>{u.get('total',0)}</b>\n"
                    f"⭐️ To'lagan Stars: <b>{u.get('stars_paid',0)}</b>\n"
                    f"📅 Qo'shilgan: <b>{u.get('joined','?')}</b>\n"
                    f"🔄 Oxirgi faollik: <b>{u.get('last_active','?')}</b>\n"
                    f"👫 Referallar: <b>{len(u.get('referrals',[]))} kishi</b>\n"
                    f"👤 Kimdan kelgan: <b>{u.get('referred_by') or 'Yoq'}</b>\n"
                    "🎁 Ref bonus berildi: <b>{}</b>\n".format("Ha ✅" if u.get("referral_rewarded") else "Yo'q") +
                    f"💰 Referaldan ishlagan: <b>{u.get('ref_earned',0)}⚡️</b>\n"
                    f"🚫 Ban: <b>{banned_s}</b>",
                    parse_mode="HTML",
                    reply_markup=InlineKeyboardMarkup([
                        [InlineKeyboardButton(T("add_balance"), callback_data=f"adm:qbal:{target_uid}"),
                         InlineKeyboardButton(T("ban_unban2"),    callback_data=f"adm:qban:{target_uid}")],
                        [InlineKeyboardButton(T("back_admin"),   callback_data="adm:menu")]
                    ]))
            context.user_data["admin_state"] = None
        except:
            await update.message.reply_text(T("m_bad_id"))
        raise ApplicationHandlerStop

    if admin_state == "ban_user":
        try:
            parts = text.split(); target_uid, action = int(parts[0]), parts[1].lower()
            if action not in ("ban", "unban"): raise ValueError
            _ban_txt_result = [None]
            def _ban_txt_mutate(users):
                k = str(target_uid)
                if k not in users:
                    get_user(target_uid)   # RLock reentrant — deadlock yo'q
                    users.update(load_users())
                if k not in users:
                    return
                users[k]["banned"] = (action == "ban")
                _ban_txt_result[0] = users[k]["banned"]
            _users_tx(_ban_txt_mutate)
            if _ban_txt_result[0] is None: raise KeyError
            emoji = "🚫" if action == "ban" else "✅"
            label = "banlandi" if action == "ban" else "ban olib tashlandi"
            await update.message.reply_text(
                T("fs5", v0=(emoji), v1=(target_uid), v2=(label)), parse_mode="HTML", reply_markup=back_kb)
            context.user_data["admin_state"] = None
        except:
            await update.message.reply_text(T("m_fmt_ban"), parse_mode="HTML")
        raise ApplicationHandlerStop

    if admin_state == "broadcast":
        users = load_users()
        total  = sum(1 for u in users.values() if not u.get("banned"))
        sent, failed = 0, 0
        status_msg = await update.message.reply_text(T("fs98", v0=(total)))
        i = 0
        for uid_str, u in users.items():
            if u.get("banned"): continue
            try:
                await context.bot.send_message(int(uid_str), text, parse_mode="HTML")
                sent += 1
            except: failed += 1
            i += 1
            if i % 25 == 0:
                try: await status_msg.edit_text(T("fs99", v0=(i), v1=(total)))
                except: pass
            await asyncio.sleep(0.05)
        await status_msg.edit_text(
            T("fs31", v0=(sent), v1=(failed)),
            parse_mode="HTML", reply_markup=back_kb)
        context.user_data["admin_state"] = None
        raise ApplicationHandlerStop

    # ── PROMO: 1-qadam — kod nomi ────────────────────────────
    if admin_state == "promo_new_name":
        code = text.strip().upper()
        if not code.replace("_", "").replace("-", "").isalnum():
            await update.message.reply_text(
                T("m_code_fmt"),
                parse_mode="HTML")
            raise ApplicationHandlerStop
        promos = load_promos()
        if code in promos:
            await update.message.reply_text(
                T("fs65", v0=(code)),
                parse_mode="HTML")
            raise ApplicationHandlerStop
        context.user_data["admin_promo_draft"] = {"code": code}
        context.user_data["admin_state"] = "promo_new_tangacha"
        await update.message.reply_text(
            T("fs84", v0=(code)),
            parse_mode="HTML", reply_markup=back_kb)
        raise ApplicationHandlerStop

    # ── PROMO: 2-qadam — tangacha miqdori ───────────────────
    if admin_state == "promo_new_tangacha":
        try:
            amount = int(text)
            if amount <= 0: raise ValueError
        except ValueError:
            await update.message.reply_text(T("m_pos_int"), parse_mode="HTML")
            raise ApplicationHandlerStop
        context.user_data["admin_promo_draft"]["tangacha"] = amount
        context.user_data["admin_state"] = "promo_new_limit"
        await update.message.reply_text(
            T("fs85"),
            parse_mode="HTML", reply_markup=back_kb)
        raise ApplicationHandlerStop

    # ── PROMO: 3-qadam — limit ──────────────────────────────
    if admin_state == "promo_new_limit":
        try:
            limit = int(text)
            if limit < 0: raise ValueError
        except ValueError:
            await update.message.reply_text(T("m_nonneg"), parse_mode="HTML")
            raise ApplicationHandlerStop
        context.user_data["admin_promo_draft"]["limit"] = limit
        context.user_data["admin_state"] = "promo_new_expires"
        await update.message.reply_text(
            T("fs86"),
            parse_mode="HTML", reply_markup=back_kb)
        raise ApplicationHandlerStop

    # ── PROMO: 4-qadam — muddat va tasdiqlash ───────────────
    if admin_state == "promo_new_expires":
        draft = context.user_data.get("admin_promo_draft", {})
        raw_exp = text.strip()
        if raw_exp.lower() == "yoq":
            expires = None
        else:
            import re as _re
            if not _re.match(r"^\d{4}-\d{2}-\d{2}$", raw_exp):
                await update.message.reply_text(
                    T("m_date_fmt"),
                    parse_mode="HTML")
                raise ApplicationHandlerStop
            expires = raw_exp
        code     = draft["code"]
        tangacha = draft["tangacha"]
        limit    = draft["limit"]
        async with _promos_lock:
            promos = load_promos()
            promos[code] = {
                "tangacha": tangacha,
                "limit":    limit,
                "used_by":  [],
                "expires":  expires,
            }
            save_promos(promos)
        exp_s   = expires or "muddatsiz"
        lim_s   = str(limit) if limit else "cheksiz"
        await update.message.reply_text(
            T("fs33", v0=(code), v1=(tangacha), v2=(lim_s), v3=(exp_s)),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton(T("promo_list"), callback_data="adm:promos")],
                [InlineKeyboardButton(T("back_admin"),     callback_data="adm:menu")],
            ]))
        context.user_data["admin_state"] = None
        context.user_data.pop("admin_promo_draft", None)
        raise ApplicationHandlerStop

    # ── PROMO: O'CHIRISH ─────────────────────────────────────
    if admin_state == "promo_del_name":
        code_to_del = text.strip().upper()
        async with _promos_lock:
            promos = load_promos()
            matched = next((k for k in promos if k.upper() == code_to_del), None)
            if not matched:
                await update.message.reply_text(
                    T("fs66", v0=(code_to_del)), parse_mode="HTML")
                raise ApplicationHandlerStop
            del promos[matched]
            save_promos(promos)
        await update.message.reply_text(
            T("fs26", v0=(matched)),
            parse_mode="HTML",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton(T("promo_list"), callback_data="adm:promos")],
                [InlineKeyboardButton(T("back_admin"),     callback_data="adm:menu")],
            ]))
        context.user_data["admin_state"] = None
        raise ApplicationHandlerStop

