async def persistent_btn_handler(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """ReplyKeyboard pastki tugmalarini qayta ishlaydi."""
    text = update.message.text
    uid  = update.effective_user.id
    # Rus/ingliz tugma matnini o'zbekcha asosiyga normallash
