    # ── Global error handler (#6): barcha kutilmagan xatolarni ushlaydi, bot o'chmasin ──
    async def _global_error_handler(update, context):
        if isinstance(context.error, TelegramConflict):
            logger.warning("Telegram Conflict aniqlandi — 15s kutib qayta ulanish...")
            await asyncio.sleep(15)
            return  # PTB polling ni davom ettiradi
        # Boshqa barcha xatolar: to'liq traceback log ga, userga qisqa xabar
        logger.error("Kutilmagan xato: update=%r", update, exc_info=context.error)
        if update and update.effective_chat:
            try:
                await context.bot.send_message(
                    chat_id=update.effective_chat.id,
                    text=T("emt11"))
            except Exception:
                pass   # xabar yuborib bo'lmasa ham bot o'chmasin

    app.add_error_handler(_global_error_handler)

    _start_custom_models_watcher()
    app.run_polling(drop_pending_updates=True, allowed_updates=Update.ALL_TYPES)

